// Auto-generated — atos (NVI)
// Do NOT edit manually. Re-run scripts/download-bible.mjs to update.

export const ATOS_NVI: Record<number, string[]> = {
  1: ["Estimado Teófilo, en mi primer libro me referí a todo lo que Jesús comenzó a hacer y enseñar","hasta el día en que fue llevado al cielo, luego de darles instrucciones por medio del Espíritu Santo a los apóstoles que había escogido.","Después de padecer la muerte, se les presentó dándoles muchas pruebas convincentes de que estaba vivo. Durante cuarenta días se les apareció y les habló acerca del reino de Dios.","Una vez, mientras comía con ellos, les ordenó: —No se alejen de Jerusalén, sino esperen la promesa del Padre, de la cual les he hablado:","Juan bautizó con[1] agua, pero dentro de pocos días ustedes serán bautizados con el Espíritu Santo.","Entonces los que estaban reunidos con él le preguntaron: —Señor, ¿es ahora cuando vas a restablecer el reino a Israel?","—No les toca a ustedes conocer la hora ni el momento determinados por la autoridad misma del Padre —les contestó Jesús—.","Pero, cuando venga el Espíritu Santo sobre ustedes, recibirán poder y serán mis testigos tanto en Jerusalén como en toda Judea y Samaria, y hasta los confines de la tierra.","Habiendo dicho esto, mientras ellos lo miraban, fue llevado a las alturas hasta que una nube lo ocultó de su vista.","Ellos se quedaron mirando fijamente al cielo mientras él se alejaba. De repente, se les acercaron dos hombres vestidos de blanco, que les dijeron:","—Galileos, ¿qué hacen aquí mirando al cielo? Este mismo Jesús, que ha sido llevado de entre ustedes al cielo, vendrá otra vez de la misma manera que lo han visto irse.","Entonces regresaron a Jerusalén desde el monte llamado de los Olivos, situado aproximadamente a un kilómetro de la ciudad.[2]","Cuando llegaron, subieron al lugar donde se alojaban. Estaban allí Pedro, Juan, Jacobo, Andrés, Felipe, Tomás, Bartolomé, Mateo, Jacobo hijo de Alfeo, Simón el Zelote y Judas hijo de Jacobo.","Todos, en un mismo espíritu, se dedicaban a la oración, junto con las mujeres y con los hermanos de Jesús y su madre María.","Por aquellos días Pedro se puso de pie en medio de los creyentes,[3] que eran un grupo como de ciento veinte personas,","y les dijo: «Hermanos, tenía que cumplirse la Escritura que, por boca de David, había predicho el Espíritu Santo en cuanto a Judas, el que sirvió de guía a los que arrestaron a Jesús.","Judas se contaba entre los nuestros y participaba en nuestro ministerio.","(Con el dinero que obtuvo por su crimen, Judas compró un terreno; allí cayó de cabeza, se reventó, y se le salieron las vísceras.","Todos en Jerusalén se enteraron de ello, así que aquel terreno fue llamado Acéldama, que en su propio idioma quiere decir “Campo de Sangre”).","»Porque en el libro de los Salmos —continuó Pedro— está escrito: »“Que su lugar quede desierto, y que nadie lo habite”.[4] También está escrito: »“Que otro se haga cargo de su oficio”.[5]","Por tanto, es preciso que se una a nosotros uno de los que nos acompañaban todo el tiempo que el Señor Jesús vivió entre nosotros,","desde que Juan bautizaba hasta el día en que Jesús fue tomado de entre nosotros y recibido en las alturas. Es necesario que uno de ellos sea junto a nosotros testigo de la resurrección».","Así que propusieron a dos: a José, llamado Barsabás, apodado el Justo, y a Matías.","Y oraron así: «Señor, tú que conoces el corazón de todos, muéstranos a cuál de estos dos has elegido","para que se haga cargo del servicio apostólico que Judas dejó para irse al lugar que le correspondía».","Luego echaron suertes y la elección recayó en Matías; así que él fue reconocido junto con los once apóstoles."],
  2: ["Cuando llegó el día de Pentecostés, estaban todos juntos en el mismo lugar.","De repente, vino del cielo un ruido como el de una violenta ráfaga de viento y llenó toda la casa donde estaban reunidos.","Se les aparecieron entonces unas lenguas como de fuego que se repartieron y se posaron sobre cada uno de ellos.","Todos fueron llenos del Espíritu Santo y comenzaron a hablar en diferentes lenguas, según el Espíritu les concedía expresarse.","Estaban de visita en Jerusalén judíos piadosos, procedentes de todas las naciones de la tierra.","Al oír aquel bullicio, se agolparon y quedaron todos pasmados porque cada uno los escuchaba hablar en su propio idioma.","Desconcertados y maravillados, decían: «¿No son galileos todos estos que están hablando?","¿Cómo es que cada uno de nosotros los oye hablar en su lengua materna?","Partos, medos y elamitas; habitantes de Mesopotamia, de Judea y de Capadocia, del Ponto y de Asia,","de Frigia y de Panfilia, de Egipto y de las regiones de Libia cercanas a Cirene; visitantes llegados de Roma;","judíos y prosélitos; cretenses y árabes: ¡todos por igual los oímos proclamar en nuestra propia lengua las maravillas de Dios!»","Desconcertados y perplejos, se preguntaban: «¿Qué quiere decir esto?»","Otros se burlaban y decían: «Lo que pasa es que están borrachos».","Entonces Pedro, con los once, se puso de pie y dijo a voz en cuello: «Compatriotas judíos y todos ustedes que están en Jerusalén, déjenme explicarles lo que sucede; presten atención a lo que les voy a decir.","Estos no están borrachos, como suponen ustedes. ¡Apenas son las nueve de la mañana![6]","En realidad lo que pasa es lo que anunció el profeta Joel:","»“Sucederá que en los últimos días —dice Dios—, derramaré mi Espíritu sobre todo el género humano. Los hijos y las hijas de ustedes profetizarán, tendrán visiones los jóvenes y sueños los ancianos.","En esos días derramaré mi Espíritu aun sobre mis siervos y mis siervas, y profetizarán.","Arriba en el cielo y abajo en la tierra mostraré prodigios: sangre, fuego y nubes de humo.","El sol se convertirá en tinieblas y la luna en sangre antes que llegue el día del Señor, día grande y esplendoroso.","Y todo el que invoque el nombre del Señor será salvo”.[7]","»Pueblo de Israel, escuchen esto: Jesús de Nazaret fue un hombre acreditado por Dios ante ustedes con milagros, señales y prodigios, los cuales realizó Dios entre ustedes por medio de él, como bien lo saben.","Este fue entregado según el determinado propósito y el previo conocimiento de Dios; y, por medio de gente malvada,[8] ustedes lo mataron, clavándolo en la cruz.","Sin embargo, Dios lo resucitó, librándolo de las angustias de la muerte, porque era imposible que la muerte lo mantuviera bajo su dominio.","En efecto, David dijo de él: »“Veía yo al Señor siempre delante de mí, porque él está a mi derecha para que no caiga.","Por eso mi corazón se alegra, y canta con gozo mi lengua; mi cuerpo también vivirá en esperanza.","No dejarás que mi vida termine en el sepulcro;[9] no permitirás que tu santo sufra corrupción.","Me has dado a conocer los caminos de la vida; me llenarás de alegría en tu presencia”.[10]","»Hermanos, permítanme hablarles con franqueza acerca del patriarca David, que murió y fue sepultado, y cuyo sepulcro está entre nosotros hasta el día de hoy.","Era profeta y sabía que Dios le había prometido bajo juramento poner en el trono a uno de sus descendientes.[11]","Fue así como previó lo que iba a suceder. Refiriéndose a la resurrección del Mesías, afirmó que Dios no dejaría que su vida terminara en el sepulcro, ni que su fin fuera la corrupción.","A este Jesús, Dios lo resucitó, y de ello todos nosotros somos testigos.","Exaltado por el poder[12] de Dios, y habiendo recibido del Padre el Espíritu Santo prometido, ha derramado esto que ustedes ahora ven y oyen.","David no subió al cielo, y sin embargo declaró: »“Dijo el Señor a mi Señor: Siéntate a mi derecha,","hasta que ponga a tus enemigos por estrado de tus pies”.[13]","»Por tanto, sépalo bien todo Israel que a este Jesús, a quien ustedes crucificaron, Dios lo ha hecho Señor y Mesías».","Cuando oyeron esto, todos se sintieron profundamente conmovidos y les dijeron a Pedro y a los otros apóstoles: —Hermanos, ¿qué debemos hacer?","—Arrepiéntase y bautícese cada uno de ustedes en el nombre de Jesucristo para perdón de sus pecados —les contestó Pedro—, y recibirán el don del Espíritu Santo.","En efecto, la promesa es para ustedes, para sus hijos y para todos los extranjeros,[14] es decir, para todos aquellos a quienes el Señor nuestro Dios quiera llamar.","Y con muchas otras razones les exhortaba insistentemente: —¡Sálvense de esta generación perversa!","Así, pues, los que recibieron su mensaje fueron bautizados, y aquel día se unieron a la iglesia unas tres mil personas.","Se mantenían firmes en la enseñanza de los apóstoles, en la comunión, en el partimiento del pan y en la oración.","Todos estaban asombrados por los muchos prodigios y señales que realizaban los apóstoles.","Todos los creyentes estaban juntos y tenían todo en común:","vendían sus propiedades y posesiones, y compartían sus bienes entre sí según la necesidad de cada uno.","No dejaban de reunirse en el templo ni un solo día. De casa en casa partían el pan y compartían la comida con alegría y generosidad,","alabando a Dios y disfrutando de la estimación general del pueblo. Y cada día el Señor añadía al grupo los que iban siendo salvos."],
  3: ["Un día subían Pedro y Juan al templo a las tres de la tarde,[15] que es la hora de la oración.","Junto a la puerta llamada Hermosa había un hombre lisiado de nacimiento, al que todos los días dejaban allí para que pidiera limosna a los que entraban en el templo.","Cuando este vio que Pedro y Juan estaban por entrar, les pidió limosna.","Pedro, con Juan, mirándolo fijamente, le dijo: —¡Míranos!","El hombre fijó en ellos la mirada, esperando recibir algo.","—No tengo plata ni oro —declaró Pedro—, pero lo que tengo te doy. En el nombre de Jesucristo de Nazaret, ¡levántate y anda!","Y tomándolo por la mano derecha, lo levantó. Al instante los pies y los tobillos del hombre cobraron fuerza.","De un salto se puso en pie y comenzó a caminar. Luego entró con ellos en el templo con sus propios pies, saltando y alabando a Dios.","Cuando todo el pueblo lo vio caminar y alabar a Dios,","lo reconocieron como el mismo hombre que acostumbraba pedir limosna sentado junto a la puerta llamada Hermosa, y se llenaron de admiración y asombro por lo que le había ocurrido.","Mientras el hombre seguía aferrado a Pedro y a Juan, toda la gente, que no salía de su asombro, corrió hacia ellos al lugar conocido como Pórtico de Salomón.","Al ver esto, Pedro les dijo: «Pueblo de Israel, ¿por qué les sorprende lo que ha pasado? ¿Por qué nos miran como si, por nuestro propio poder o virtud, hubiéramos hecho caminar a este hombre?","El Dios de Abraham, de Isaac y de Jacob, el Dios de nuestros antepasados, ha glorificado a su siervo Jesús. Ustedes lo entregaron y lo rechazaron ante Pilato, aunque este había decidido soltarlo.","Rechazaron al Santo y Justo, y pidieron que se indultara a un asesino.","Mataron al autor de la vida, pero Dios lo levantó de entre los muertos, y de eso nosotros somos testigos.","Por la fe en el nombre de Jesús, él ha restablecido a este hombre a quien ustedes ven y conocen. Esta fe que viene por medio de Jesús lo ha sanado por completo, como les consta a ustedes.","»Ahora bien, hermanos, yo sé que ustedes y sus dirigentes actuaron así por ignorancia.","Pero de este modo Dios cumplió lo que de antemano había anunciado por medio de todos los profetas: que su Mesías tenía que padecer.","Por tanto, para que sean borrados sus pecados, arrepiéntanse y vuélvanse a Dios, a fin de que vengan tiempos de descanso de parte del Señor,","enviándoles el Mesías que ya había sido preparado para ustedes, el cual es Jesús.","Es necesario que él permanezca en el cielo hasta que llegue el tiempo de la restauración de todas las cosas, como Dios lo ha anunciado desde hace siglos por medio de sus santos profetas.","Moisés dijo: “El Señor su Dios hará surgir para ustedes, de entre sus propios hermanos, a un profeta como yo; presten atención a todo lo que les diga.","Porque quien no le haga caso será eliminado del pueblo”.[16]","»En efecto, a partir de Samuel todos los profetas han anunciado estos días.","Ustedes, pues, son herederos de los profetas y del pacto que Dios estableció con nuestros antepasados al decirle a Abraham: “Todos los pueblos del mundo serán bendecidos por medio de tu descendencia”.[17]","Cuando Dios resucitó a su siervo, lo envió primero a ustedes para darles la bendición de que cada uno se convierta de sus maldades»."],
  4: ["Mientras Pedro y Juan le hablaban a la gente, se les presentaron los sacerdotes, el capitán de la guardia del templo y los saduceos.","Estaban muy disgustados porque los apóstoles enseñaban a la gente y proclamaban la resurrección, que se había hecho evidente en el caso de Jesús.","Prendieron a Pedro y a Juan y, como ya anochecía, los metieron en la cárcel hasta el día siguiente.","Pero muchos de los que oyeron el mensaje creyeron, y el número de estos, contando solo a los hombres, llegaba a unos cinco mil.","Al día siguiente se reunieron en Jerusalén los gobernantes, los ancianos y los maestros de la ley.","Allí estaban el sumo sacerdote Anás, Caifás, Juan, Alejandro y los otros miembros de la familia del sumo sacerdote.","Hicieron que Pedro y Juan comparecieran ante ellos y comenzaron a interrogarlos: —¿Con qué poder, o en nombre de quién, hicieron ustedes esto?","Pedro, lleno del Espíritu Santo, les respondió: —Gobernantes del pueblo y ancianos:","Hoy se nos procesa por haber favorecido a un inválido, ¡y se nos pregunta cómo fue sanado!","Sepan, pues, todos ustedes y todo el pueblo de Israel que este hombre está aquí delante de ustedes, sano gracias al nombre de Jesucristo de Nazaret, crucificado por ustedes, pero resucitado por Dios.","Jesucristo es »“la piedra que desecharon ustedes los constructores, y que ha llegado a ser la piedra angular”.[18]","De hecho, en ningún otro hay salvación, porque no hay bajo el cielo otro nombre dado a los hombres mediante el cual podamos ser salvos».","Los gobernantes, al ver la osadía con que hablaban Pedro y Juan, y al darse cuenta de que eran gente sin estudios ni preparación, quedaron asombrados y reconocieron que habían estado con Jesús.","Además, como vieron que los acompañaba el hombre que había sido sanado, no tenían nada que alegar.","Así que les mandaron que se retiraran del Consejo, y se pusieron a deliberar entre sí:","«¿Qué vamos a hacer con estos sujetos? Es un hecho que por medio de ellos ha ocurrido un milagro evidente; todos los que viven en Jerusalén lo saben, y no podemos negarlo.","Pero, para evitar que este asunto siga divulgándose entre la gente, vamos a amenazarlos para que no vuelvan a hablar de ese nombre a nadie».","Los llamaron y les ordenaron terminantemente que dejaran de hablar y enseñar acerca del nombre de Jesús.","Pero Pedro y Juan replicaron: —¿Es justo delante de Dios obedecerlos a ustedes en vez de obedecerlo a él? ¡Júzguenlo ustedes mismos!","Nosotros no podemos dejar de hablar de lo que hemos visto y oído.","Después de nuevas amenazas, los dejaron irse. Por causa de la gente, no hallaban manera de castigarlos: todos alababan a Dios por lo que había sucedido,","pues el hombre que había sido milagrosamente sanado tenía más de cuarenta años.","Al quedar libres, Pedro y Juan volvieron a los suyos y les relataron todo lo que les habían dicho los jefes de los sacerdotes y los ancianos.","Cuando lo oyeron, alzaron unánimes la voz en oración a Dios: «Soberano Señor, creador del cielo y de la tierra, del mar y de todo lo que hay en ellos,","tú, por medio del Espíritu Santo, dijiste en labios de nuestro padre David, tu siervo: »“¿Por qué se sublevan las naciones y en vano conspiran los pueblos?","Los reyes de la tierra se rebelan y los gobernantes se confabulan contra el Señor y contra su ungido”.[19]","En efecto, en esta ciudad se reunieron Herodes y Poncio Pilato, con los gentiles y con el pueblo[20] de Israel, contra tu santo siervo Jesús, a quien ungiste","para hacer lo que de antemano tu poder y tu voluntad habían determinado que sucediera.","Ahora, Señor, toma en cuenta sus amenazas y concede a tus siervos el proclamar tu palabra sin temor alguno.","Por eso, extiende tu mano para sanar y hacer señales y prodigios mediante el nombre de tu santo siervo Jesús».","Después de haber orado, tembló el lugar en que estaban reunidos; todos fueron llenos del Espíritu Santo, y proclamaban la palabra de Dios sin temor alguno.","Todos los creyentes eran de un solo sentir y pensar. Nadie consideraba suya ninguna de sus posesiones, sino que las compartían.","Los apóstoles, a su vez, con gran poder seguían dando testimonio de la resurrección del Señor Jesús. La gracia de Dios se derramaba abundantemente sobre todos ellos,","pues no había ningún necesitado en la comunidad. Quienes poseían casas o terrenos los vendían, llevaban el dinero de las ventas","y lo entregaban a los apóstoles para que se distribuyera a cada uno según su necesidad.","José, un levita natural de Chipre, a quien los apóstoles llamaban Bernabé (que significa: Consolador[21]),","vendió un terreno que poseía, llevó el dinero y lo puso a disposición de los apóstoles."],
  5: ["Un hombre llamado Ananías, con su esposa Safira, también vendió una propiedad.","En complicidad con su esposa, se quedó con parte del dinero y puso el resto a disposición de los apóstoles.","—Ananías —le reclamó Pedro—, ¿cómo es posible que Satanás haya llenado tu corazón para que le mintieras al Espíritu Santo y te quedaras con parte del dinero que recibiste por el terreno?","¿Acaso no era tuyo antes de venderlo? Y una vez vendido, ¿no estaba el dinero en tu poder? ¿Cómo se te ocurrió hacer esto? ¡No has mentido a los hombres, sino a Dios!","Al oír estas palabras, Ananías cayó muerto. Y un gran temor se apoderó de todos los que se enteraron de lo sucedido.","Entonces se acercaron los más jóvenes, envolvieron el cuerpo, se lo llevaron y le dieron sepultura.","Unas tres horas más tarde entró la esposa, sin saber lo que había ocurrido.","—Dime —le preguntó Pedro—, ¿vendieron ustedes el terreno por tal precio? —Sí —dijo ella—, por tal precio.","—¿Por qué se pusieron de acuerdo para poner a prueba al Espíritu del Señor? —le recriminó Pedro—. ¡Mira! Los que sepultaron a tu esposo acaban de regresar y ahora te llevarán a ti.","En ese mismo instante ella cayó muerta a los pies de Pedro. Entonces entraron los jóvenes y, al verla muerta, se la llevaron y le dieron sepultura al lado de su esposo.","Y un gran temor se apoderó de toda la iglesia y de todos los que se enteraron de estos sucesos.","Por medio de los apóstoles ocurrían muchas señales y prodigios entre el pueblo; y todos los creyentes se reunían de común acuerdo en el Pórtico de Salomón.","Nadie entre el pueblo se atrevía a juntarse con ellos, aunque los elogiaban.","Y seguía aumentando el número de los que confiaban en el Señor.","Era tal la multitud de hombres y mujeres que hasta sacaban a los enfermos a las plazas y los ponían en camillas para que, al pasar Pedro, por lo menos su sombra cayera sobre alguno de ellos.","También de los pueblos vecinos a Jerusalén acudían multitudes que llevaban personas enfermas y atormentadas por espíritus malignos, y todas eran sanadas.","El sumo sacerdote y todos sus partidarios, que pertenecían a la secta de los saduceos, se llenaron de envidia.","Entonces arrestaron a los apóstoles y los metieron en la cárcel común.","Pero en la noche un ángel del Señor abrió las puertas de la cárcel y los sacó.","«Vayan —les dijo—, preséntense en el templo y comuniquen al pueblo todo este mensaje de vida».","Conforme a lo que habían oído, al amanecer entraron en el templo y se pusieron a enseñar. Cuando llegaron el sumo sacerdote y sus partidarios, convocaron al Consejo, es decir, a la asamblea general de los ancianos de Israel, y mandaron traer de la cárcel a los apóstoles.","Pero, al llegar los guardias a la cárcel, no los encontraron. Así que volvieron con el siguiente informe:","«Encontramos la cárcel cerrada, con todas las medidas de seguridad, y a los guardias firmes a las puertas; pero, cuando abrimos, no encontramos a nadie adentro».","Al oírlo, el capitán de la guardia del templo y los jefes de los sacerdotes se quedaron perplejos, preguntándose en qué terminaría todo aquello.","En esto, se presentó alguien que les informó: «¡Miren! Los hombres que ustedes metieron en la cárcel están en el templo y siguen enseñando al pueblo».","Fue entonces el capitán con sus guardias y trajo a los apóstoles sin recurrir a la fuerza, porque temían ser apedreados por la gente.","Los condujeron ante el Consejo, y el sumo sacerdote les reclamó:","—Terminantemente les hemos prohibido enseñar en ese nombre. Sin embargo, ustedes han llenado a Jerusalén con sus enseñanzas, y se han propuesto echarnos la culpa a nosotros de la muerte[22] de ese hombre.","—¡Es necesario obedecer a Dios antes que a los hombres! —respondieron Pedro y los demás apóstoles—.","El Dios de nuestros antepasados resucitó a Jesús, a quien ustedes mataron colgándolo de un madero.","Por su poder,[23] Dios lo exaltó como Príncipe y Salvador, para que diera a Israel arrepentimiento y perdón de pecados.","Nosotros somos testigos de estos acontecimientos, y también lo es el Espíritu Santo que Dios ha dado a quienes le obedecen.","A los que oyeron esto se les subió la sangre a la cabeza y querían matarlos.","Pero un fariseo llamado Gamaliel, maestro de la ley muy respetado por todo el pueblo, se puso de pie en el Consejo y mandó que hicieran salir por un momento a los apóstoles.","Luego dijo: «Hombres de Israel, piensen dos veces en lo que están a punto de hacer con estos hombres.","Hace algún tiempo surgió Teudas, jactándose de ser alguien, y se le unieron unos cuatrocientos hombres. Pero lo mataron y todos sus seguidores se dispersaron y allí se acabó todo.","Después de él surgió Judas el galileo, en los días del censo, y logró que la gente lo siguiera. A él también lo mataron, y todos sus secuaces se dispersaron.","En este caso les aconsejo que dejen a estos hombres en paz. ¡Suéltenlos! Si lo que se proponen y hacen es de origen humano, fracasará;","pero, si es de Dios, no podrán destruirlos, y ustedes se encontrarán luchando contra Dios». Se dejaron persuadir por Gamaliel.","Entonces llamaron a los apóstoles y, luego de azotarlos, les ordenaron que no hablaran más en el nombre de Jesús. Después de eso los soltaron.","Así, pues, los apóstoles salieron del Consejo, llenos de gozo por haber sido considerados dignos de sufrir afrentas por causa del Nombre.","Y día tras día, en el templo y de casa en casa, no dejaban de enseñar y anunciar las buenas nuevas de que Jesús es el Mesías."],
  6: ["En aquellos días, al aumentar el número de los discípulos, se quejaron los judíos de habla griega contra los de habla aramea[24] de que sus viudas eran desatendidas en la distribución diaria de los alimentos.","Así que los doce reunieron a toda la comunidad de discípulos y les dijeron: «No está bien que nosotros los apóstoles descuidemos el ministerio de la palabra de Dios para servir las mesas.","Hermanos, escojan de entre ustedes a siete hombres de buena reputación, llenos del Espíritu y de sabiduría, para encargarles esta responsabilidad.","Así nosotros nos dedicaremos de lleno a la oración y al ministerio de la palabra».","Esta propuesta agradó a toda la asamblea. Escogieron a Esteban, hombre lleno de fe y del Espíritu Santo, y a Felipe, a Prócoro, a Nicanor, a Timón, a Parmenas y a Nicolás, un prosélito de Antioquía.","Los presentaron a los apóstoles, quienes oraron y les impusieron las manos.","Y la palabra de Dios se difundía: el número de los discípulos aumentaba considerablemente en Jerusalén, e incluso muchos de los sacerdotes obedecían a la fe.","Esteban, hombre lleno de la gracia y del poder de Dios, hacía grandes prodigios y señales milagrosas entre el pueblo.","Con él se pusieron a discutir ciertos individuos de la sinagoga llamada de los Libertos, donde había judíos de Cirene y de Alejandría, de Cilicia y de la provincia de Asia.","Como no podían hacer frente a la sabiduría ni al Espíritu con que hablaba Esteban,","instigaron a unos hombres a decir: «Hemos oído a Esteban blasfemar contra Moisés y contra Dios».","Agitaron al pueblo, a los ancianos y a los maestros de la ley. Se apoderaron de Esteban y lo llevaron ante el Consejo.","Presentaron testigos falsos, que declararon: «Este hombre no deja de hablar contra este lugar santo y contra la ley.","Le hemos oído decir que ese Jesús de Nazaret destruirá este lugar y cambiará las tradiciones que nos dejó Moisés».","Todos los que estaban sentados en el Consejo fijaron la mirada en Esteban y vieron que su rostro se parecía al de un ángel."],
  7: ["—¿Son ciertas estas acusaciones? —le preguntó el sumo sacerdote.","Él contestó: —Hermanos y padres, ¡escúchenme! El Dios de la gloria se apareció a nuestro padre Abraham cuando este aún vivía en Mesopotamia, antes de radicarse en Jarán.","“Deja tu tierra y a tus parientes —le dijo Dios—, y ve a la tierra que yo te mostraré”.[25]","»Entonces salió de la tierra de los caldeos y se estableció en Jarán. Desde allí, después de la muerte de su padre, Dios lo trasladó a esta tierra donde ustedes viven ahora.","No le dio herencia alguna en ella, ni siquiera dónde plantar el pie, pero le prometió dársela en posesión a él y a su descendencia, aunque Abraham no tenía ni un solo hijo todavía.","Dios le dijo así: “Tus descendientes vivirán como extranjeros en tierra extraña, donde serán esclavizados y maltratados durante cuatrocientos años.","Pero, sea cual sea la nación que los esclavice, yo la castigaré, y luego tus descendientes saldrán de esa tierra y me adorarán en este lugar”.[26]","Hizo con Abraham el pacto que tenía por señal la circuncisión. Así, cuando Abraham tuvo a su hijo Isaac, lo circuncidó a los ocho días de nacido, e Isaac a Jacob, y Jacob a los doce patriarcas.","»Por envidia los patriarcas vendieron a José como esclavo, quien fue llevado a Egipto; pero Dios estaba con él","y lo libró de todas sus desgracias. Le dio sabiduría para ganarse el favor del faraón, rey de Egipto, que lo nombró gobernador del país y del palacio real.","»Hubo entonces un hambre que azotó a todo Egipto y a Canaán, causando mucho sufrimiento, y nuestros antepasados no encontraban alimentos.","Al enterarse Jacob de que había comida en Egipto, mandó allá a nuestros antepasados en una primera visita.","En la segunda, José se dio a conocer a sus hermanos, y el faraón supo del origen de José.","Después de esto, José mandó llamar a su padre Jacob y a toda su familia, setenta y cinco personas en total.","Bajó entonces Jacob a Egipto, y allí murieron él y nuestros antepasados.","Sus restos fueron llevados a Siquén y puestos en el sepulcro que a buen precio Abraham había comprado a los hijos de Jamor en Siquén.","»Cuando ya se acercaba el tiempo de que se cumpliera la promesa que Dios le había hecho a Abraham, el pueblo crecía y se multiplicaba en Egipto.","Por aquel entonces subió al trono de Egipto un nuevo rey que no sabía nada de José.","Este rey usó de artimañas con nuestro pueblo y oprimió a nuestros antepasados, obligándolos a dejar abandonados a sus hijos recién nacidos para que murieran.","»En aquel tiempo nació Moisés, y fue agradable a los ojos de Dios.[27] Por tres meses se crió en la casa de su padre","y, al quedar abandonado, la hija del faraón lo adoptó y lo crió como a su propio hijo.","Así Moisés fue instruido en toda la sabiduría de los egipcios, y era poderoso en palabra y en obra.","»Cuando cumplió cuarenta años, Moisés tuvo el deseo de allegarse a sus hermanos israelitas.","Al ver que un egipcio maltrataba a uno de ellos, acudió en su defensa y lo vengó matando al egipcio.","Moisés suponía que sus hermanos reconocerían que Dios iba a liberarlos por medio de él, pero ellos no lo comprendieron así.","Al día siguiente, Moisés sorprendió a dos israelitas que estaban peleando. Trató de reconciliarlos, diciéndoles: “Señores, ustedes son hermanos; ¿por qué quieren hacerse daño?”","»Pero el que estaba maltratando al otro empujó a Moisés y le dijo: “¿Y quién te nombró a ti gobernante y juez sobre nosotros?","¿Acaso quieres matarme a mí, como mataste ayer al egipcio?”[28]","Al oír esto, Moisés huyó a Madián; allí vivió como extranjero y tuvo dos hijos.","»Pasados cuarenta años, se le apareció un ángel en el desierto cercano al monte Sinaí, en las llamas de una zarza que ardía.","Moisés se asombró de lo que veía. Al acercarse para observar, oyó la voz del Señor:","“Yo soy el Dios de tus antepasados, el Dios de Abraham, de Isaac y de Jacob”.[29] Moisés se puso a temblar de miedo, y no se atrevía a mirar.","»Le dijo el Señor: “Quítate las sandalias, porque estás pisando tierra santa.","Ciertamente he visto la opresión que sufre mi pueblo en Egipto. Los he escuchado quejarse, así que he descendido para librarlos. Ahora ven y te enviaré de vuelta a Egipto”.[30]","»A este mismo Moisés, a quien habían rechazado diciéndole: “¿Y quién te nombró gobernante y juez?”, Dios lo envió para ser gobernante y libertador, mediante el poder del ángel que se le apareció en la zarza.","Él los sacó de Egipto haciendo prodigios y señales milagrosas tanto en la tierra de Egipto como en el Mar Rojo, y en el desierto durante cuarenta años.","»Este Moisés les dijo a los israelitas: “Dios hará surgir para ustedes, de entre sus propios hermanos, un profeta como yo”.[31]","Este mismo Moisés estuvo en la asamblea en el desierto, con el ángel que le habló en el monte Sinaí, y con nuestros antepasados. Fue también él quien recibió palabras de vida para comunicárnoslas a nosotros.","»Nuestros antepasados no quisieron obedecerlo a él, sino que lo rechazaron. Lo que realmente deseaban era volver a Egipto,","por lo cual le dijeron a Aarón: “Tienes que hacernos dioses que vayan delante de nosotros, porque a ese Moisés que nos sacó de Egipto, ¡no sabemos qué pudo haberle pasado!”[32]","»Entonces se hicieron un ídolo en forma de becerro. Le ofrecieron sacrificios y tuvieron fiesta en honor de la obra de sus manos.","Pero Dios les volvió la espalda y los entregó a que rindieran culto a los astros. Así está escrito en el libro de los profetas: »“Casa de Israel, ¿acaso me ofrecieron ustedes sacrificios y ofrendas durante los cuarenta años en el desierto?","Por el contrario, ustedes se hicieron cargo del tabernáculo de Moloc, de la estrella del dios Refán, y de las imágenes que hicieron para adorarlas. Por lo tanto, los mandaré al exilio”[33] más allá de Babilonia.","»Nuestros antepasados tenían en el desierto el tabernáculo del testimonio, hecho como Dios le había ordenado a Moisés, según el modelo que este había visto.","Después de haber recibido el tabernáculo, lo trajeron consigo bajo el mando de Josué, cuando conquistaron la tierra de las naciones que Dios expulsó de la presencia de ellos. Allí permaneció hasta el tiempo de David,","quien disfrutó del favor de Dios y pidió que le permitiera proveer una morada para el Dios[34] de Jacob.","Pero fue Salomón quien construyó la casa.","»Sin embargo, el Altísimo no habita en casas construidas por manos humanas. Como dice el profeta:","»“El cielo es mi trono, y la tierra, el estrado de mis pies. ¿Qué clase de casa me construirán? —dice el Señor—. ¿O qué lugar de descanso?","¿No es mi mano la que ha hecho todas estas cosas?”[35]","»¡Tercos, duros de corazón y torpes de oídos![36] Ustedes son iguales que sus antepasados: ¡Siempre resisten al Espíritu Santo!","¿A cuál de los profetas no persiguieron sus antepasados? Ellos mataron a los que de antemano anunciaron la venida del Justo, y ahora a este lo han traicionado y asesinado","ustedes, que recibieron la ley promulgada por medio de ángeles y no la han obedecido».","Al oír esto, rechinando los dientes montaron en cólera contra él.","Pero Esteban, lleno del Espíritu Santo, fijó la mirada en el cielo y vio la gloria de Dios, y a Jesús de pie a la derecha de Dios.","—¡Veo el cielo abierto —exclamó—, y al Hijo del hombre de pie a la derecha de Dios!","Entonces ellos, gritando a voz en cuello, se taparon los oídos y todos a una se abalanzaron sobre él,","lo sacaron a empellones fuera de la ciudad y comenzaron a apedrearlo. Los acusadores le encargaron sus mantos a un joven llamado Saulo.","Mientras lo apedreaban, Esteban oraba. —Señor Jesús —decía—, recibe mi espíritu.","Luego cayó de rodillas y gritó: —¡Señor, no les tomes en cuenta este pecado! Cuando hubo dicho esto, murió."],
  8: ["Y Saulo estaba allí, aprobando la muerte de Esteban. Aquel día se desató una gran persecución contra la iglesia en Jerusalén, y todos, excepto los apóstoles, se dispersaron por las regiones de Judea y Samaria.","Unos hombres piadosos sepultaron a Esteban e hicieron gran duelo por él.","Saulo, por su parte, causaba estragos en la iglesia: entrando de casa en casa, arrastraba a hombres y mujeres y los metía en la cárcel.","Los que se habían dispersado predicaban la palabra por dondequiera que iban.","Felipe bajó a una ciudad de Samaria y les anunciaba al Mesías.","Al oír a Felipe y ver las señales milagrosas que realizaba, mucha gente se reunía y todos prestaban atención a su mensaje.","De muchos endemoniados los espíritus malignos salían dando alaridos, y un gran número de paralíticos y cojos quedaban sanos.","Y aquella ciudad se llenó de alegría.","Ya desde antes había en esa ciudad un hombre llamado Simón que, jactándose de ser un gran personaje, practicaba la hechicería y asombraba a la gente de Samaria.","Todos, desde el más pequeño hasta el más grande, le prestaban atención y exclamaban: «¡Este hombre es al que llaman el Gran Poder de Dios!»","Lo seguían porque por mucho tiempo los había tenido deslumbrados con sus artes mágicas.","Pero, cuando creyeron a Felipe, que les anunciaba las buenas nuevas del reino de Dios y el nombre de Jesucristo, tanto hombres como mujeres se bautizaron.","Simón mismo creyó y, después de bautizarse, seguía a Felipe por todas partes, asombrado de los grandes milagros y señales que veía.","Cuando los apóstoles que estaban en Jerusalén se enteraron de que los samaritanos habían aceptado la palabra de Dios, les enviaron a Pedro y a Juan.","Estos, al llegar, oraron por ellos para que recibieran el Espíritu Santo,","porque el Espíritu aún no había descendido sobre ninguno de ellos; solamente habían sido bautizados en el nombre del Señor Jesús.","Entonces Pedro y Juan les impusieron las manos, y ellos recibieron el Espíritu Santo.","Al ver Simón que mediante la imposición de las manos de los apóstoles se daba el Espíritu Santo, les ofreció dinero","y les pidió: —Denme también a mí ese poder, para que todos a quienes yo les imponga las manos reciban el Espíritu Santo.","—¡Que tu dinero perezca contigo —le contestó Pedro—, porque intentaste comprar el don de Dios con dinero!","No tienes arte ni parte en este asunto, porque no eres íntegro delante de Dios.","Por eso, arrepiéntete de tu maldad y ruega al Señor. Tal vez te perdone el haber tenido esa mala intención.","Veo que vas camino a la amargura y a la esclavitud del pecado.","—Rueguen al Señor por mí —respondió Simón—, para que no me suceda nada de lo que han dicho.","Después de testificar y proclamar la palabra del Señor, Pedro y Juan se pusieron en camino de vuelta a Jerusalén, y de paso predicaron el evangelio en muchas poblaciones de los samaritanos.","Un ángel del Señor le dijo a Felipe: «Ponte en marcha hacia el sur, por el camino del desierto que baja de Jerusalén a Gaza».","Felipe emprendió el viaje, y resulta que se encontró con un etíope eunuco, alto funcionario encargado de todo el tesoro de la Candace, reina de los etíopes. Este había ido a Jerusalén para adorar","y, en el viaje de regreso a su país, iba sentado en su carroza, leyendo el libro del profeta Isaías.","El Espíritu le dijo a Felipe: «Acércate y júntate a ese carro».","Felipe se acercó de prisa a la carroza y, al oír que el hombre leía al profeta Isaías, le preguntó: —¿Acaso entiende usted lo que está leyendo?","—¿Y cómo voy a entenderlo —contestó— si nadie me lo explica? Así que invitó a Felipe a subir y sentarse con él.","El pasaje de la Escritura que estaba leyendo era el siguiente: «Como oveja, fue llevado al matadero; y como cordero que enmudece ante su trasquilador, ni siquiera abrió su boca.","Lo humillaron y no le hicieron justicia. ¿Quién describirá su descendencia? Porque su vida fue arrancada de la tierra».[37]","—Dígame usted, por favor, ¿de quién habla aquí el profeta, de sí mismo o de algún otro? —le preguntó el eunuco a Felipe.","Entonces Felipe, comenzando con ese mismo pasaje de la Escritura, le anunció las buenas nuevas acerca de Jesús.","Mientras iban por el camino, llegaron a un lugar donde había agua, y dijo el eunuco: —Mire usted, aquí hay agua. ¿Qué impide que yo sea bautizado?[38]","Entonces mandó parar la carroza, y ambos bajaron al agua, y Felipe lo bautizó.","Cuando subieron del agua, el Espíritu del Señor se llevó de repente a Felipe. El eunuco no volvió a verlo, pero siguió alegre su camino.","En cuanto a Felipe, apareció en Azoto, y se fue predicando el evangelio en todos los pueblos hasta que llegó a Cesarea."],
  9: ["Mientras tanto, Saulo, respirando aún amenazas de muerte contra los discípulos del Señor, se presentó al sumo sacerdote","y le pidió cartas de extradición para las sinagogas de Damasco. Tenía la intención de encontrar y llevarse presos a Jerusalén a todos los que pertenecieran al Camino, fueran hombres o mujeres.","En el viaje sucedió que, al acercarse a Damasco, una luz del cielo relampagueó de repente a su alrededor.","Él cayó al suelo y oyó una voz que le decía: —Saulo, Saulo, ¿por qué me persigues?","—¿Quién eres, Señor? —preguntó. —Yo soy Jesús, a quien tú persigues —le contestó la voz—.","Levántate y entra en la ciudad, que allí se te dirá lo que tienes que hacer.","Los hombres que viajaban con Saulo se detuvieron atónitos, porque oían la voz, pero no veían a nadie.","Saulo se levantó del suelo, pero cuando abrió los ojos no podía ver, así que lo tomaron de la mano y lo llevaron a Damasco.","Estuvo ciego tres días, sin comer ni beber nada.","Había en Damasco un discípulo llamado Ananías, a quien el Señor llamó en una visión. —¡Ananías! —Aquí estoy, Señor.","—Anda, ve a la casa de Judas, en la calle llamada Derecha, y pregunta por un tal Saulo de Tarso. Está orando,","y ha visto en una visión a un hombre llamado Ananías, que entra y pone las manos sobre él para que recobre la vista.","Entonces Ananías respondió: —Señor, he oído hablar mucho de ese hombre y de todo el mal que ha causado a tus santos en Jerusalén.","Y ahora lo tenemos aquí, autorizado por los jefes de los sacerdotes, para llevarse presos a todos los que invocan tu nombre.","—¡Ve! —insistió el Señor—, porque ese hombre es mi instrumento escogido para dar a conocer mi nombre tanto a las naciones y a sus reyes como al pueblo de Israel.","Yo le mostraré cuánto tendrá que padecer por mi nombre.","Ananías se fue y, cuando llegó a la casa, le impuso las manos a Saulo y le dijo: «Hermano Saulo, el Señor Jesús, que se te apareció en el camino, me ha enviado para que recobres la vista y seas lleno del Espíritu Santo».","Al instante cayó de los ojos de Saulo algo como escamas, y recobró la vista. Se levantó y fue bautizado;","y, habiendo comido, recobró las fuerzas. Saulo pasó varios días con los discípulos que estaban en Damasco,","y en seguida se dedicó a predicar en las sinagogas, afirmando que Jesús es el Hijo de Dios.","Todos los que le oían quedaban asombrados, y preguntaban: «¿No es este el que en Jerusalén perseguía a muerte a los que invocan ese nombre? ¿Y no ha venido aquí para llevárselos presos y entregarlos a los jefes de los sacerdotes?»","Pero Saulo cobraba cada vez más fuerza y confundía a los judíos que vivían en Damasco, demostrándoles que Jesús es el Mesías.","Después de muchos días, los judíos se pusieron de acuerdo para hacerlo desaparecer,","pero Saulo se enteró de sus maquinaciones. Día y noche vigilaban de cerca las puertas de la ciudad con el fin de eliminarlo.","Pero sus discípulos se lo llevaron de noche y lo bajaron en un canasto por una abertura en la muralla.","Cuando llegó a Jerusalén, trataba de juntarse con los discípulos, pero todos tenían miedo de él, porque no creían que de veras fuera discípulo.","Entonces Bernabé lo tomó a su cargo y lo llevó a los apóstoles. Saulo les describió en detalle cómo en el camino había visto al Señor, el cual le había hablado, y cómo en Damasco había predicado con libertad en el nombre de Jesús.","Así que se quedó con ellos, y andaba por todas partes en Jerusalén, hablando abiertamente en el nombre del Señor.","Conversaba y discutía con los judíos de habla griega,[39] pero ellos se proponían eliminarlo.","Cuando se enteraron de ello los hermanos, se lo llevaron a Cesarea y de allí lo mandaron a Tarso.","Mientras tanto, la iglesia disfrutaba de paz a la vez que se consolidaba en toda Judea, Galilea y Samaria, pues vivía en el temor del Señor. E iba creciendo en número, fortalecida por el Espíritu Santo.","Pedro, que estaba recorriendo toda la región, fue también a visitar a los santos que vivían en Lida.","Allí encontró a un paralítico llamado Eneas, que llevaba ocho años en cama.","«Eneas —le dijo Pedro—, Jesucristo te sana. Levántate y tiende tu cama». Y al instante se levantó.","Todos los que vivían en Lida y en Sarón lo vieron, y se convirtieron al Señor.","Había en Jope una discípula llamada Tabita (que traducido es Dorcas[40]). Esta se esmeraba en hacer buenas obras y en ayudar a los pobres.","Sucedió que en esos días cayó enferma y murió. Pusieron el cadáver, después de lavarlo, en un cuarto de la planta alta.","Y como Lida estaba cerca de Jope, los discípulos, al enterarse de que Pedro se encontraba en Lida, enviaron a dos hombres a rogarle: «¡Por favor, venga usted a Jope en seguida!»","Sin demora, Pedro se fue con ellos, y cuando llegó lo llevaron al cuarto de arriba. Todas las viudas se presentaron, llorando y mostrándole las túnicas y otros vestidos que Dorcas había hecho cuando aún estaba con ellas.","Pedro hizo que todos salieran del cuarto; luego se puso de rodillas y oró. Volviéndose hacia la muerta, dijo: «Tabita, levántate». Ella abrió los ojos y, al ver a Pedro, se incorporó.","Él, tomándola de la mano, la levantó. Luego llamó a los creyentes y a las viudas, a quienes la presentó viva.","La noticia se difundió por todo Jope, y muchos creyeron en el Señor.","Pedro se quedó en Jope un buen tiempo, en casa de un tal Simón, que era curtidor."],
  10: ["Vivía en Cesarea un centurión llamado Cornelio, del regimiento conocido como el Italiano.","Él y toda su familia eran devotos y temerosos de Dios. Realizaba muchas obras de beneficencia para el pueblo de Israel y oraba a Dios constantemente.","Un día, como a las tres de la tarde,[41] tuvo una visión. Vio claramente a un ángel de Dios que se le acercaba y le decía: —¡Cornelio!","—¿Qué quieres, Señor? —le preguntó Cornelio, mirándolo fijamente y con mucho miedo. —Dios ha recibido tus oraciones y tus obras de beneficencia como una ofrenda —le contestó el ángel—.","Envía de inmediato a algunos hombres a Jope para que hagan venir a un tal Simón, apodado Pedro.","Él se hospeda con Simón el curtidor, que tiene su casa junto al mar.","Después de que se fue el ángel que le había hablado, Cornelio llamó a dos de sus siervos y a un soldado devoto de los que le servían regularmente.","Les explicó todo lo que había sucedido y los envió a Jope.","Al día siguiente, mientras ellos iban de camino y se acercaban a la ciudad, Pedro subió a la azotea a orar. Era casi el mediodía.[42]","Tuvo hambre y quiso algo de comer. Mientras se lo preparaban, le sobrevino un éxtasis.","Vio el cielo abierto y algo parecido a una gran sábana que, suspendida por las cuatro puntas, descendía hacia la tierra.","En ella había toda clase de cuadrúpedos, como también reptiles y aves.","—Levántate, Pedro; mata y come —le dijo una voz.","—¡De ninguna manera, Señor! —replicó Pedro—. Jamás he comido nada impuro o inmundo.","Por segunda vez le insistió la voz: —Lo que Dios ha purificado, tú no lo llames impuro.","Esto sucedió tres veces, y en seguida la sábana fue recogida al cielo.","Pedro no atinaba a explicarse cuál podría ser el significado de la visión. Mientras tanto, los hombres enviados por Cornelio, que estaban preguntando por la casa de Simón, se presentaron a la puerta.","Llamando, averiguaron si allí se hospedaba Simón, apodado Pedro.","Mientras Pedro seguía reflexionando sobre el significado de la visión, el Espíritu le dijo: «Mira, Simón, tres[43] hombres te buscan.","Date prisa, baja y no dudes en ir con ellos, porque yo los he enviado».","Pedro bajó y les dijo a los hombres: —Aquí estoy; yo soy el que ustedes buscan. ¿Qué asunto los ha traído por acá?","Ellos le contestaron: —Venimos de parte del centurión Cornelio, un hombre justo y temeroso de Dios, respetado por todo el pueblo judío. Un ángel de Dios le dio instrucciones de invitarlo a usted a su casa para escuchar lo que usted tiene que decirle.","Entonces Pedro los invitó a pasar y los hospedó. Al día siguiente, Pedro se fue con ellos acompañado de algunos creyentes de Jope.","Un día después llegó a Cesarea. Cornelio estaba esperándolo con los parientes y amigos íntimos que había reunido.","Al llegar Pedro a la casa, Cornelio salió a recibirlo y, postrándose delante de él, le rindió homenaje.","Pero Pedro hizo que se levantara, y le dijo: —Ponte de pie, que solo soy un hombre como tú.","Pedro entró en la casa conversando con él, y encontró a muchos reunidos.","Entonces les habló así: —Ustedes saben muy bien que nuestra ley prohíbe que un judío se junte con un extranjero o lo visite. Pero Dios me ha hecho ver que a nadie debo llamar impuro o inmundo.","Por eso, cuando mandaron por mí, vine sin poner ninguna objeción. Ahora permítanme preguntarles: ¿para qué me hicieron venir?","Cornelio contestó: —Hace cuatro días a esta misma hora, las tres de la tarde, estaba yo en casa orando.[44] De repente apareció delante de mí un hombre vestido con ropa brillante,","y me dijo: “Cornelio, Dios ha oído tu oración y se ha acordado de tus obras de beneficencia.","Por lo tanto, envía a alguien a Jope para hacer venir a Simón, apodado Pedro, que se hospeda en casa de Simón el curtidor, junto al mar”.","Así que inmediatamente mandé a llamarte, y tú has tenido la bondad de venir. Ahora estamos todos aquí, en la presencia de Dios, para escuchar todo lo que el Señor te ha encomendado que nos digas.","Pedro tomó la palabra, y dijo: —Ahora comprendo que en realidad para Dios no hay favoritismos,","sino que en toda nación él ve con agrado a los que le temen y actúan con justicia.","Dios envió su mensaje al pueblo de Israel, anunciando las buenas nuevas de la paz por medio de Jesucristo, que es el Señor de todos.","Ustedes conocen este mensaje que se difundió por toda Judea, comenzando desde Galilea, después del bautismo que predicó Juan.","Me refiero a Jesús de Nazaret: cómo lo ungió Dios con el Espíritu Santo y con poder, y cómo anduvo haciendo el bien y sanando a todos los que estaban oprimidos por el diablo, porque Dios estaba con él.","Nosotros somos testigos de todo lo que hizo en la tierra de los judíos y en Jerusalén. Lo mataron, colgándolo de un madero,","pero Dios lo resucitó al tercer día y dispuso que se apareciera,","no a todo el pueblo, sino a nosotros, testigos previamente escogidos por Dios, que comimos y bebimos con él después de su resurrección.","Él nos mandó a predicar al pueblo y a dar solemne testimonio de que ha sido nombrado por Dios como juez de vivos y muertos.","De él dan testimonio todos los profetas, que todo el que cree en él recibe, por medio de su nombre, el perdón de los pecados.","Mientras Pedro estaba todavía hablando, el Espíritu Santo descendió sobre todos los que escuchaban el mensaje.","Los defensores de la circuncisión que habían llegado con Pedro se quedaron asombrados de que el don del Espíritu Santo se hubiera derramado también sobre los gentiles,","pues los oían hablar en lenguas y alabar a Dios. Entonces Pedro respondió:","—¿Acaso puede alguien negar el agua para que sean bautizados estos que han recibido el Espíritu Santo lo mismo que nosotros?","Y mandó que fueran bautizados en el nombre de Jesucristo. Entonces le pidieron que se quedara con ellos algunos días."],
  11: ["Los apóstoles y los hermanos de toda Judea se enteraron de que también los gentiles habían recibido la palabra de Dios.","Así que cuando Pedro subió a Jerusalén, los defensores de la circuncisión lo criticaron","diciendo: —Entraste en casa de hombres incircuncisos y comiste con ellos.","Entonces Pedro comenzó a explicarles paso a paso lo que había sucedido:","—Yo estaba orando en la ciudad de Jope y tuve en éxtasis una visión. Vi que del cielo descendía algo parecido a una gran sábana que, suspendida por las cuatro puntas, bajaba hasta donde yo estaba.","Me fijé en lo que había en ella, y vi cuadrúpedos, fieras, reptiles y aves.","Luego oí una voz que me decía: “Levántate, Pedro; mata y come”.","Repliqué: “¡De ninguna manera, Señor! Jamás ha entrado en mi boca nada impuro o inmundo”.","Por segunda vez insistió la voz del cielo: “Lo que Dios ha purificado, tú no lo llames impuro”.","Esto sucedió tres veces, y luego todo volvió a ser llevado al cielo.","»En aquel momento se presentaron en la casa donde yo estaba tres hombres que desde Cesarea habían sido enviados a verme.","El Espíritu me dijo que fuera con ellos sin dudar. También fueron conmigo estos seis hermanos, y entramos en la casa de aquel hombre.","Él nos contó cómo en su casa se le había aparecido un ángel que le dijo: “Manda a alguien a Jope para hacer venir a Simón, apodado Pedro.","Él te traerá un mensaje mediante el cual serán salvos tú y toda tu familia”.","»Cuando comencé a hablarles, el Espíritu Santo descendió sobre ellos tal como al principio descendió sobre nosotros.","Entonces recordé lo que había dicho el Señor: “Juan bautizó con[45] agua, pero ustedes serán bautizados con el Espíritu Santo”.","Por tanto, si Dios les ha dado a ellos el mismo don que a nosotros al creer en el Señor Jesucristo, ¿quién soy yo para pretender estorbar a Dios?»","Al oír esto, se apaciguaron y alabaron a Dios diciendo: —¡Así que también a los gentiles les ha concedido Dios el arrepentimiento para vida!","Los que se habían dispersado a causa de la persecución que se desató por el caso de Esteban llegaron hasta Fenicia, Chipre y Antioquía, sin anunciar a nadie el mensaje excepto a los judíos.","Sin embargo, había entre ellos algunas personas de Chipre y de Cirene que, al llegar a Antioquía, comenzaron a hablarles también a los de habla griega, anunciándoles las buenas nuevas acerca del Señor Jesús.","El poder del Señor estaba con ellos, y un gran número creyó y se convirtió al Señor.","La noticia de estos sucesos llegó a oídos de la iglesia de Jerusalén, y mandaron a Bernabé a Antioquía.","Cuando él llegó y vio las evidencias de la gracia de Dios, se alegró y animó a todos a hacerse el firme propósito de permanecer fieles al Señor,","pues era un hombre bueno, lleno del Espíritu Santo y de fe. Un gran número de personas aceptó al Señor.","Después partió Bernabé para Tarso en busca de Saulo,","y, cuando lo encontró, lo llevó a Antioquía. Durante todo un año se reunieron los dos con la iglesia y enseñaron a mucha gente. Fue en Antioquía donde a los discípulos se les llamó «cristianos» por primera vez.","Por aquel tiempo unos profetas bajaron de Jerusalén a Antioquía.","Uno de ellos, llamado Ágabo, se puso de pie y predijo por medio del Espíritu que iba a haber una gran hambre en todo el mundo, lo cual sucedió durante el reinado de Claudio.","Entonces decidieron que cada uno de los discípulos, según los recursos de cada cual, enviaría ayuda a los hermanos que vivían en Judea.","Así lo hicieron, mandando su ofrenda a los ancianos por medio de Bernabé y de Saulo."],
  12: ["En ese tiempo el rey Herodes hizo arrestar a algunos de la iglesia con el fin de maltratarlos.","A Jacobo, hermano de Juan, lo mandó matar a espada.","Al ver que esto agradaba a los judíos, procedió a prender también a Pedro. Esto sucedió durante la fiesta de los Panes sin levadura.","Después de arrestarlo, lo metió en la cárcel y lo puso bajo la vigilancia de cuatro grupos de cuatro soldados cada uno. Tenía la intención de hacerlo comparecer en juicio público después de la Pascua.","Pero, mientras mantenían a Pedro en la cárcel, la iglesia oraba constante y fervientemente a Dios por él.","La misma noche en que Herodes estaba a punto de sacar a Pedro para someterlo a juicio, este dormía entre dos soldados, sujeto con dos cadenas. Unos guardias vigilaban la entrada de la cárcel.","De repente apareció un ángel del Señor y una luz resplandeció en la celda. Despertó a Pedro con unas palmadas en el costado y le dijo: «¡Date prisa, levántate!» Las cadenas cayeron de las manos de Pedro.","Le dijo además el ángel: «Vístete y cálzate las sandalias». Así lo hizo, y el ángel añadió: «Échate la capa encima y sígueme».","Pedro salió tras él, pero no sabía si realmente estaba sucediendo lo que el ángel hacía. Le parecía que se trataba de una visión.","Pasaron por la primera y la segunda guardia, y llegaron al portón de hierro que daba a la ciudad. El portón se les abrió por sí solo, y salieron. Caminaron unas cuadras, y de repente el ángel lo dejó solo.","Entonces Pedro volvió en sí y se dijo: «Ahora estoy completamente seguro de que el Señor ha enviado a su ángel para librarme del poder de Herodes y de todo lo que el pueblo judío esperaba».","Cuando cayó en cuenta de esto, fue a casa de María, la madre de Juan, apodado Marcos, donde muchas personas estaban reunidas orando.","Llamó a la puerta de la calle, y salió a responder una criada llamada Rode.","Al reconocer la voz de Pedro, se puso tan contenta que volvió corriendo sin abrir. —¡Pedro está a la puerta! —exclamó.","—¡Estás loca! —le dijeron. Ella insistía en que así era, pero los otros decían: —Debe de ser su ángel.","Entre tanto, Pedro seguía llamando. Cuando abrieron la puerta y lo vieron, quedaron pasmados.","Con la mano Pedro les hizo señas de que se callaran, y les contó cómo el Señor lo había sacado de la cárcel. —Cuéntenles esto a Jacobo y a los hermanos —les dijo. Luego salió y se fue a otro lugar.","Al amanecer se produjo un gran alboroto entre los soldados respecto al paradero de Pedro.","Herodes hizo averiguaciones, pero, al no encontrarlo, les tomó declaración a los guardias y mandó matarlos. Después viajó de Judea a Cesarea y se quedó allí.","Herodes estaba furioso con los de Tiro y de Sidón, pero ellos se pusieron de acuerdo y se presentaron ante él. Habiéndose ganado el favor de Blasto, camarero del rey, pidieron paz, porque su región dependía del país del rey para obtener sus provisiones.","El día señalado, Herodes, ataviado con su ropaje real y sentado en su trono, le dirigió un discurso al pueblo.","La gente gritaba: «¡Voz de un dios, no de hombre!»","Al instante un ángel del Señor lo hirió, porque no le había dado la gloria a Dios; y Herodes murió comido de gusanos.","Pero la palabra de Dios seguía extendiéndose y difundiéndose.","Cuando Bernabé y Saulo cumplieron su servicio, regresaron de[46] Jerusalén llevando con ellos a Juan, llamado también Marcos."],
  13: ["En la iglesia de Antioquía eran profetas y maestros Bernabé; Simeón, apodado el Negro; Lucio de Cirene; Manaén, que se había criado con Herodes el tetrarca; y Saulo.","Mientras ayunaban y participaban en el culto al Señor, el Espíritu Santo dijo: «Apártenme ahora a Bernabé y a Saulo para el trabajo al que los he llamado».","Así que después de ayunar, orar e imponerles las manos, los despidieron.","Bernabé y Saulo, enviados por el Espíritu Santo, bajaron a Seleucia, y de allí navegaron a Chipre.","Al llegar a Salamina, predicaron la palabra de Dios en las sinagogas de los judíos. Tenían también a Juan como ayudante.","Recorrieron toda la isla hasta Pafos. Allí se encontraron con un hechicero, un falso profeta judío llamado Barjesús,","que estaba con el gobernador[47] Sergio Paulo. El gobernador, hombre inteligente, mandó llamar a Bernabé y a Saulo, en un esfuerzo por escuchar la palabra de Dios.","Pero Elimas el hechicero (que es lo que significa su nombre) se les oponía y procuraba apartar de la fe al gobernador.","Entonces Saulo, o sea Pablo, lleno del Espíritu Santo, clavó los ojos en Elimas y le dijo:","«¡Hijo del diablo y enemigo de toda justicia, lleno de todo tipo de engaño y de fraude! ¿Nunca dejarás de torcer los caminos rectos del Señor?","Ahora la mano del Señor está contra ti; vas a quedarte ciego y por algún tiempo no podrás ver la luz del sol». Al instante cayeron sobre él sombra y oscuridad, y comenzó a buscar a tientas a alguien que lo llevara de la mano.","Al ver lo sucedido, el gobernador creyó, maravillado de la enseñanza acerca del Señor.","Pablo y sus compañeros se hicieron a la mar desde Pafos, y llegaron a Perge de Panfilia. Juan se separó de ellos y regresó a Jerusalén;","ellos, por su parte, siguieron su viaje desde Perge hasta Antioquía de Pisidia. El sábado entraron en la sinagoga y se sentaron.","Al terminar la lectura de la ley y los profetas, los jefes de la sinagoga mandaron a decirles: «Hermanos, si tienen algún mensaje de aliento para el pueblo, hablen».","Pablo se puso en pie, hizo una señal con la mano y dijo: «Escúchenme, israelitas, y ustedes, los gentiles temerosos de Dios:","El Dios de este pueblo de Israel escogió a nuestros antepasados y engrandeció al pueblo mientras vivían como extranjeros en Egipto. Con gran poder los sacó de aquella tierra","y soportó su mal proceder[48] en el desierto unos cuarenta años.","Luego de destruir siete naciones en Canaán, dio a su pueblo la tierra de ellas en herencia.","Todo esto duró unos cuatrocientos cincuenta años. »Después de esto, Dios les asignó jueces hasta los días del profeta Samuel.","Entonces pidieron un rey, y Dios les dio a Saúl, hijo de Quis, de la tribu de Benjamín, que gobernó por cuarenta años.","Tras destituir a Saúl, les puso por rey a David, de quien dio este testimonio: “He encontrado en David, hijo de Isaí, un hombre conforme a mi corazón; él realizará todo lo que yo quiero”.","»De los descendientes de este, conforme a la promesa, Dios ha provisto a Israel un Salvador, que es Jesús.","Antes de la venida de Jesús, Juan predicó un bautismo de arrepentimiento a todo el pueblo de Israel.","Cuando estaba completando su carrera, Juan decía: “¿Quién suponen ustedes que soy? No soy aquel. Miren, después de mí viene uno a quien no soy digno ni siquiera de desatarle las sandalias”.","»Hermanos, descendientes de Abraham, y ustedes, los gentiles temerosos de Dios: a nosotros se nos ha enviado este mensaje de salvación.","Los habitantes de Jerusalén y sus gobernantes no reconocieron a Jesús. Por tanto, al condenarlo, cumplieron las palabras de los profetas que se leen todos los sábados.","Aunque no encontraron ninguna causa digna de muerte, le pidieron a Pilato que lo mandara a ejecutar.","Después de llevar a cabo todas las cosas que estaban escritas acerca de él, lo bajaron del madero y lo sepultaron.","Pero Dios lo levantó de entre los muertos.","Durante muchos días lo vieron los que habían subido con él de Galilea a Jerusalén, y ellos son ahora sus testigos ante el pueblo.","»Nosotros les anunciamos a ustedes las buenas nuevas respecto a la promesa hecha a nuestros antepasados.","Dios nos la ha cumplido plenamente a nosotros, los descendientes de ellos, al resucitar a Jesús. Como está escrito en el segundo salmo: »“Tú eres mi hijo; hoy mismo te he engendrado”.[49]","Dios lo resucitó para que no volviera jamás a la corrupción. Así se cumplieron estas palabras: »“Yo les daré las bendiciones santas y seguras prometidas a David”.[50]","Por eso dice en otro pasaje: »“No permitirás que el fin de tu santo sea la corrupción”.[51]","»Ciertamente David, después de servir a su propia generación conforme al propósito de Dios, murió, fue sepultado con sus antepasados, y su cuerpo sufrió la corrupción.","Pero aquel a quien Dios resucitó no sufrió la corrupción de su cuerpo.","»Por tanto, hermanos, sepan que por medio de Jesús se les anuncia a ustedes el perdón de los pecados.","Ustedes no pudieron ser justificados de esos pecados por la ley de Moisés, pero todo el que cree es justificado por medio de Jesús.","Tengan cuidado, no sea que les suceda lo que han dicho los profetas:","»“¡Miren, burlones! ¡Asómbrense y desaparezcan! Estoy por hacer en estos días una obra que ustedes nunca creerán, aunque alguien se la explique”».[52]","Al salir ellos de la sinagoga, los invitaron a que el siguiente sábado les hablaran más de estas cosas.","Cuando se disolvió la asamblea, muchos judíos y prosélitos fieles acompañaron a Pablo y a Bernabé, los cuales en su conversación con ellos les instaron a perseverar en la gracia de Dios.","El siguiente sábado casi toda la ciudad se congregó para oír la palabra del Señor.","Pero, cuando los judíos vieron a las multitudes, se llenaron de celos y contradecían con maldiciones lo que Pablo decía.","Pablo y Bernabé les contestaron valientemente: «Era necesario que les anunciáramos la palabra de Dios primero a ustedes. Como la rechazan y no se consideran dignos de la vida eterna, ahora vamos a dirigirnos a los gentiles.","Así nos lo ha mandado el Señor: »“Te he puesto por luz para las naciones, a fin de que lleves mi salvación hasta los confines de la tierra”».[53]","Al oír esto, los gentiles se alegraron y celebraron la palabra del Señor; y creyeron todos los que estaban destinados a la vida eterna.","La palabra del Señor se difundía por toda la región.","Pero los judíos incitaron a mujeres muy distinguidas y favorables al judaísmo, y a los hombres más prominentes de la ciudad, y provocaron una persecución contra Pablo y Bernabé. Por tanto, los expulsaron de la región.","Ellos, por su parte, se sacudieron el polvo de los pies en señal de protesta contra la ciudad, y se fueron a Iconio.","Y los discípulos quedaron llenos de alegría y del Espíritu Santo."],
  14: ["En Iconio, Pablo y Bernabé entraron, como de costumbre, en la sinagoga judía y hablaron de tal manera que creyó una multitud de judíos y de griegos.","Pero los judíos incrédulos incitaron a los gentiles y les amargaron el ánimo contra los hermanos.","En todo caso, Pablo y Bernabé pasaron allí bastante tiempo, hablando valientemente en el nombre del Señor, quien confirmaba el mensaje de su gracia haciendo señales y prodigios por medio de ellos.","La gente de la ciudad estaba dividida: unos estaban de parte de los judíos, y otros de parte de los apóstoles.","Hubo un complot tanto de los gentiles como de los judíos, apoyados por sus dirigentes, para maltratarlos y apedrearlos.","Al darse cuenta de esto, los apóstoles huyeron a Listra y a Derbe, ciudades de Licaonia, y a sus alrededores,","donde siguieron anunciando las buenas nuevas.","En Listra vivía un hombre lisiado de nacimiento, que no podía mover las piernas y nunca había caminado. Estaba sentado,","escuchando a Pablo, quien al reparar en él y ver que tenía fe para ser sanado,","le ordenó con voz fuerte: —¡Ponte en pie y enderézate! El hombre dio un salto y empezó a caminar.","Al ver lo que Pablo había hecho, la gente comenzó a gritar en el idioma de Licaonia: —¡Los dioses han tomado forma humana y han venido a visitarnos!","A Bernabé lo llamaban Zeus, y a Pablo, Hermes, porque era el que dirigía la palabra.","El sacerdote de Zeus, el dios cuyo templo estaba a las afueras de la ciudad, llevó toros y guirnaldas a las puertas y, con toda la multitud, quería ofrecerles sacrificios.","Al enterarse de esto los apóstoles Bernabé y Pablo, se rasgaron las vestiduras y se lanzaron por entre la multitud, gritando:","—Señores, ¿por qué hacen esto? Nosotros también somos hombres mortales como ustedes. Las buenas nuevas que les anunciamos son que dejen estas cosas sin valor y se vuelvan al Dios viviente, que hizo el cielo, la tierra, el mar y todo lo que hay en ellos.","En épocas pasadas él permitió que todas las naciones siguieran su propio camino.","Sin embargo, no ha dejado de dar testimonio de sí mismo haciendo el bien, dándoles lluvias del cielo y estaciones fructíferas, proporcionándoles comida y alegría de corazón.","A pesar de todo lo que dijeron, a duras penas evitaron que la multitud les ofreciera sacrificios.","En eso llegaron de Antioquía y de Iconio unos judíos que hicieron cambiar de parecer a la multitud. Apedrearon a Pablo y lo arrastraron fuera de la ciudad, creyendo que estaba muerto.","Pero, cuando lo rodearon los discípulos, él se levantó y volvió a entrar en la ciudad. Al día siguiente, partió para Derbe en compañía de Bernabé.","Después de anunciar las buenas nuevas en aquella ciudad y de hacer muchos discípulos, Pablo y Bernabé regresaron a Listra, a Iconio y a Antioquía,","fortaleciendo a los discípulos y animándolos a perseverar en la fe. «Es necesario pasar por muchas dificultades para entrar en el reino de Dios», les decían.","En cada iglesia nombraron ancianos y, con oración y ayuno, los encomendaron al Señor, en quien habían creído.","Atravesando Pisidia, llegaron a Panfilia,","y, cuando terminaron de predicar la palabra en Perge, bajaron a Atalía.","De Atalía navegaron a Antioquía, donde se los había encomendado a la gracia de Dios para la obra que ya habían realizado.","Cuando llegaron, reunieron a la iglesia e informaron de todo lo que Dios había hecho por medio de ellos, y de cómo había abierto la puerta de la fe a los gentiles.","Y se quedaron allí mucho tiempo con los discípulos."],
  15: ["Algunos que habían llegado de Judea a Antioquía se pusieron a enseñar a los hermanos: «A menos que ustedes se circunciden, conforme a la tradición de Moisés, no pueden ser salvos».","Esto provocó un altercado y un serio debate de Pablo y Bernabé con ellos. Entonces se decidió que Pablo y Bernabé, y algunos otros creyentes, subieran a Jerusalén para tratar este asunto con los apóstoles y los ancianos.","Enviados por la iglesia, al pasar por Fenicia y Samaria contaron cómo se habían convertido los gentiles. Estas noticias llenaron de alegría a todos los creyentes.","Al llegar a Jerusalén, fueron muy bien recibidos tanto por la iglesia como por los apóstoles y los ancianos, a quienes informaron de todo lo que Dios había hecho por medio de ellos.","Entonces intervinieron algunos creyentes que pertenecían a la secta de los fariseos y afirmaron: —Es necesario circuncidar a los gentiles y exigirles que obedezcan la ley de Moisés.","Los apóstoles y los ancianos se reunieron para examinar este asunto.","Después de una larga discusión, Pedro tomó la palabra: —Hermanos, ustedes saben que desde un principio Dios me escogió de entre ustedes para que por mi boca los gentiles oyeran el mensaje del evangelio y creyeran.","Dios, que conoce el corazón humano, mostró que los aceptaba dándoles el Espíritu Santo, lo mismo que a nosotros.","Sin hacer distinción alguna entre nosotros y ellos, purificó sus corazones por la fe.","Entonces, ¿por qué tratan ahora de provocar a Dios poniendo sobre el cuello de esos discípulos un yugo que ni nosotros ni nuestros antepasados hemos podido soportar?","¡No puede ser! Más bien, como ellos, creemos que somos salvos[54] por la gracia de nuestro Señor Jesús.","Toda la asamblea guardó silencio para escuchar a Bernabé y a Pablo, que les contaron las señales y prodigios que Dios había hecho por medio de ellos entre los gentiles.","Cuando terminaron, Jacobo tomó la palabra y dijo: —Hermanos, escúchenme.","Simón[55] nos ha expuesto cómo Dios desde el principio tuvo a bien escoger de entre los gentiles un pueblo para honra de su nombre.","Con esto concuerdan las palabras de los profetas, tal como está escrito:","»“Después de esto volveré y reedificaré la choza caída de David. Reedificaré sus ruinas, y la restauraré,","para que busque al Señor el resto de la humanidad, todas las naciones que llevan mi nombre.","Así dice el Señor, que hace estas cosas”[56] conocidas desde tiempos antiguos.[57]","»Por lo tanto, yo considero que debemos dejar de ponerles trabas a los gentiles que se convierten a Dios.","Más bien debemos escribirles que se abstengan de lo contaminado por los ídolos, de la inmoralidad sexual, de la carne de animales estrangulados y de sangre.","En efecto, desde tiempos antiguos Moisés siempre ha tenido en cada ciudad quien lo predique y lo lea en las sinagogas todos los sábados».","Entonces los apóstoles y los ancianos, de común acuerdo con toda la iglesia, decidieron escoger a algunos de ellos y enviarlos a Antioquía con Pablo y Bernabé. Escogieron a Judas, llamado Barsabás, y a Silas, que tenían buena reputación entre los hermanos.","Con ellos mandaron la siguiente carta: Los apóstoles y los ancianos, a nuestros hermanos gentiles en Antioquía, Siria y Cilicia: Saludos.","Nos hemos enterado de que algunos de los nuestros, sin nuestra autorización, los han inquietado a ustedes, alarmándoles con lo que les han dicho.","Así que de común acuerdo hemos decidido escoger a algunos hombres y enviarlos a ustedes con nuestros queridos hermanos Pablo y Bernabé,","quienes han arriesgado su vida por el nombre de nuestro Señor Jesucristo.","Por tanto, les enviamos a Judas y a Silas para que les confirmen personalmente lo que les escribimos.","Nos pareció bien al Espíritu Santo y a nosotros no imponerles a ustedes ninguna carga aparte de los siguientes requisitos:","abstenerse de lo sacrificado a los ídolos, de sangre, de la carne de animales estrangulados y de la inmoralidad sexual. Bien harán ustedes si evitan estas cosas. Con nuestros mejores deseos.","Una vez despedidos, ellos bajaron a Antioquía, donde reunieron a la congregación y entregaron la carta.","Los creyentes la leyeron y se alegraron por su mensaje alentador.","Judas y Silas, que también eran profetas, hablaron extensamente para animarlos y fortalecerlos.","Después de pasar algún tiempo allí, los hermanos los despidieron en paz, para que regresaran a quienes los habían enviado.[58]","Pablo y Bernabé permanecieron en Antioquía, enseñando y anunciando la palabra del Señor en compañía de muchos otros.","Algún tiempo después, Pablo le dijo a Bernabé: «Volvamos a visitar a los creyentes en todas las ciudades en donde hemos anunciado la palabra del Señor, y veamos cómo están».","Resulta que Bernabé quería llevar con ellos a Juan Marcos,","pero a Pablo no le pareció prudente llevarlo, porque los había abandonado en Panfilia y no había seguido con ellos en el trabajo.","Se produjo entre ellos un conflicto tan serio que acabaron por separarse. Bernabé se llevó a Marcos y se embarcó rumbo a Chipre,","mientras que Pablo escogió a Silas. Después de que los hermanos lo encomendaron a la gracia del Señor, Pablo partió","y viajó por Siria y Cilicia, consolidando a las iglesias."],
  16: ["Llegó Pablo a Derbe y después a Listra, donde se encontró con un discípulo llamado Timoteo, hijo de una mujer judía creyente, pero de padre griego.","Los hermanos en Listra y en Iconio hablaban bien de Timoteo,","así que Pablo decidió llevárselo. Por causa de los judíos que vivían en aquella región, lo circuncidó, pues todos sabían que su padre era griego.","Al pasar por las ciudades, entregaban los acuerdos tomados por los apóstoles y los ancianos de Jerusalén, para que los pusieran en práctica.","Y así las iglesias se fortalecían en la fe y crecían en número día tras día.","Atravesaron la región de Frigia y Galacia, ya que el Espíritu Santo les había impedido que predicaran la palabra en la provincia de Asia.","Cuando llegaron cerca de Misia, intentaron pasar a Bitinia, pero el Espíritu de Jesús no se lo permitió.","Entonces, pasando de largo por Misia, bajaron a Troas.","Durante la noche Pablo tuvo una visión en la que un hombre de Macedonia, puesto de pie, le rogaba: «Pasa a Macedonia y ayúdanos».","Después de que Pablo tuvo la visión, en seguida nos preparamos para partir hacia Macedonia, convencidos de que Dios nos había llamado a anunciar el evangelio a los macedonios.","Zarpando de Troas, navegamos directamente a Samotracia, y al día siguiente a Neápolis.","De allí fuimos a Filipos, que es una colonia romana y la ciudad principal de ese distrito de Macedonia. En esa ciudad nos quedamos varios días.","El sábado salimos a las afueras de la ciudad, y fuimos por la orilla del río, donde esperábamos encontrar un lugar de oración. Nos sentamos y nos pusimos a conversar con las mujeres que se habían reunido.","Una de ellas, que se llamaba Lidia, adoraba a Dios. Era de la ciudad de Tiatira y vendía telas de púrpura. Mientras escuchaba, el Señor le abrió el corazón para que respondiera al mensaje de Pablo.","Cuando fue bautizada con su familia, nos hizo la siguiente invitación: «Si ustedes me consideran creyente en el Señor, vengan a hospedarse en mi casa». Y nos persuadió.","Una vez, cuando íbamos al lugar de oración, nos salió al encuentro una joven esclava que tenía un espíritu de adivinación. Con sus poderes ganaba mucho dinero para sus amos.","Nos seguía a Pablo y a nosotros, gritando: —Estos hombres son siervos del Dios Altísimo, y les anuncian a ustedes el camino de salvación.","Así continuó durante muchos días. Por fin Pablo se molestó tanto que se volvió y reprendió al espíritu: —¡En el nombre de Jesucristo, te ordeno que salgas de ella! Y en aquel mismo momento el espíritu la dejó.","Cuando los amos de la joven se dieron cuenta de que se les había esfumado la esperanza de ganar dinero, echaron mano a Pablo y a Silas y los arrastraron a la plaza, ante las autoridades.","Los presentaron ante los magistrados y dijeron: —Estos hombres son judíos, y están alborotando a nuestra ciudad,","enseñando costumbres que a los romanos se nos prohíbe admitir o practicar.","Entonces la multitud se amotinó contra Pablo y Silas, y los magistrados mandaron que les arrancaran la ropa y los azotaran.","Después de darles muchos golpes, los echaron en la cárcel, y ordenaron al carcelero que los custodiara con la mayor seguridad.","Al recibir tal orden, este los metió en el calabozo interior y les sujetó los pies en el cepo.","A eso de la medianoche, Pablo y Silas se pusieron a orar y a cantar himnos a Dios, y los otros presos los escuchaban.","De repente se produjo un terremoto tan fuerte que la cárcel se estremeció hasta sus cimientos. Al instante se abrieron todas las puertas y a los presos se les soltaron las cadenas.","El carcelero despertó y, al ver las puertas de la cárcel de par en par, sacó la espada y estuvo a punto de matarse, porque pensaba que los presos se habían escapado. Pero Pablo le gritó:","—¡No te hagas ningún daño! ¡Todos estamos aquí!","El carcelero pidió luz, entró precipitadamente y se echó temblando a los pies de Pablo y de Silas.","Luego los sacó y les preguntó: —Señores, ¿qué tengo que hacer para ser salvo?","—Cree en el Señor Jesús; así tú y tu familia serán salvos —le contestaron.","Luego les expusieron la palabra de Dios a él y a todos los demás que estaban en su casa.","A esas horas de la noche, el carcelero se los llevó y les lavó las heridas; en seguida fueron bautizados él y toda su familia.","El carcelero los llevó a su casa, les sirvió comida y se alegró mucho junto con toda su familia por haber creído en Dios.","Al amanecer, los magistrados mandaron a unos guardias al carcelero con esta orden: «Suelta a esos hombres».","El carcelero, entonces, le informó a Pablo: —Los magistrados han ordenado que los suelte. Así que pueden irse. Vayan en paz.","Pero Pablo respondió a los guardias: —¿Cómo? A nosotros, que somos ciudadanos romanos, que nos han azotado públicamente y sin proceso alguno, y nos han echado en la cárcel, ¿ahora quieren expulsarnos a escondidas? ¡Nada de eso! Que vengan ellos personalmente a escoltarnos hasta la salida.","Los guardias comunicaron la respuesta a los magistrados. Estos se asustaron cuando oyeron que Pablo y Silas eran ciudadanos romanos,","así que fueron a presentarles sus disculpas. Los escoltaron desde la cárcel, pidiéndoles que se fueran de la ciudad.","Al salir de la cárcel, Pablo y Silas se dirigieron a la casa de Lidia, donde se vieron con los hermanos y los animaron. Después se fueron."],
  17: ["Atravesando Anfípolis y Apolonia, Pablo y Silas llegaron a Tesalónica, donde había una sinagoga de los judíos.","Como era su costumbre, Pablo entró en la sinagoga y tres sábados seguidos discutió con ellos. Basándose en las Escrituras,","les explicaba y demostraba que era necesario que el Mesías padeciera y resucitara. Les decía: «Este Jesús que les anuncio es el Mesías».","Algunos de los judíos se convencieron y se unieron a Pablo y a Silas, como también lo hicieron un buen número de mujeres prominentes y muchos griegos que adoraban a Dios.","Pero los judíos, llenos de envidia, reclutaron a unos maleantes callejeros, con los que armaron una turba y empezaron a alborotar la ciudad. Asaltaron la casa de Jasón en busca de Pablo y Silas, con el fin de procesarlos públicamente.","Pero, como no los encontraron, arrastraron a Jasón y a algunos otros hermanos ante las autoridades de la ciudad, gritando: «¡Estos que han trastornado el mundo entero han venido también acá,","y Jasón los ha recibido en su casa! Todos ellos actúan en contra de los decretos del emperador, afirmando que hay otro rey, uno que se llama Jesús».","Al oír esto, la multitud y las autoridades de la ciudad se alborotaron;","entonces estas exigieron fianza a Jasón y a los demás para dejarlos en libertad.","Tan pronto como se hizo de noche, los hermanos enviaron a Pablo y a Silas a Berea, quienes al llegar se dirigieron a la sinagoga de los judíos.","Estos eran de sentimientos más nobles que los de Tesalónica, de modo que recibieron el mensaje con toda avidez y todos los días examinaban las Escrituras para ver si era verdad lo que se les anunciaba.","Muchos de los judíos creyeron, y también un buen número de griegos, incluso mujeres distinguidas y no pocos hombres.","Cuando los judíos de Tesalónica se enteraron de que también en Berea estaba Pablo predicando la palabra de Dios, fueron allá para agitar y alborotar a las multitudes.","En seguida los hermanos enviaron a Pablo hasta la costa, pero Silas y Timoteo se quedaron en Berea.","Los que acompañaban a Pablo lo llevaron hasta Atenas. Luego regresaron con instrucciones de que Silas y Timoteo se reunieran con él tan pronto como les fuera posible.","Mientras Pablo los esperaba en Atenas, le dolió en el alma ver que la ciudad estaba llena de ídolos.","Así que discutía en la sinagoga con los judíos y con los griegos que adoraban a Dios, y a diario hablaba en la plaza con los que se encontraban por allí.","Algunos filósofos epicúreos y estoicos entablaron conversación con él. Unos decían: «¿Qué querrá decir este charlatán?» Otros comentaban: «Parece que es predicador de dioses extranjeros». Decían esto porque Pablo les anunciaba las buenas nuevas de Jesús y de la resurrección.","Entonces se lo llevaron a una reunión del Areópago. —¿Se puede saber qué nueva enseñanza es esta que usted presenta? —le preguntaron—.","Porque nos viene usted con ideas que nos suenan extrañas, y queremos saber qué significan.","Es que todos los atenienses y los extranjeros que vivían allí se pasaban el tiempo sin hacer otra cosa más que escuchar y comentar las últimas novedades.","Pablo se puso en medio del Areópago y tomó la palabra: —¡Ciudadanos atenienses! Observo que ustedes son sumamente religiosos en todo lo que hacen.","Al pasar y fijarme en sus lugares sagrados, encontré incluso un altar con esta inscripción: A UN DIOS DESCONOCIDO. Pues bien, eso que ustedes adoran como algo desconocido es lo que yo les anuncio.","»El Dios que hizo el mundo y todo lo que hay en él es Señor del cielo y de la tierra. No vive en templos construidos por hombres,","ni se deja servir por manos humanas, como si necesitara de algo. Por el contrario, él es quien da a todos la vida, el aliento y todas las cosas.","De un solo hombre hizo todas las naciones[59] para que habitaran toda la tierra; y determinó los períodos de su historia y las fronteras de sus territorios.","Esto lo hizo Dios para que todos lo busquen y, aunque sea a tientas, lo encuentren. En verdad, él no está lejos de ninguno de nosotros,","“puesto que en él vivimos, nos movemos y existimos”. Como algunos de sus propios poetas griegos han dicho: “De él somos descendientes”.","»Por tanto, siendo descendientes de Dios, no debemos pensar que la divinidad sea como el oro, la plata o la piedra: escultura hecha como resultado del ingenio y de la destreza del ser humano.","Pues bien, Dios pasó por alto aquellos tiempos de tal ignorancia, pero ahora manda a todos, en todas partes, que se arrepientan.","Él ha fijado un día en que juzgará al mundo con justicia, por medio del hombre que ha designado. De ello ha dado pruebas a todos al levantarlo de entre los muertos».","Cuando oyeron de la resurrección, unos se burlaron; pero otros le dijeron: —Queremos que usted nos hable en otra ocasión sobre este tema.","En ese momento Pablo salió de la reunión.","Algunas personas se unieron a Pablo y creyeron. Entre ellos estaba Dionisio, miembro del Areópago, también una mujer llamada Dámaris, y otros más."],
  18: ["Después de esto, Pablo se marchó de Atenas y se fue a Corinto.","Allí se encontró con un judío llamado Aquila, natural del Ponto, y con su esposa Priscila. Hacía poco habían llegado de Italia, porque Claudio había mandado que todos los judíos fueran expulsados de Roma. Pablo fue a verlos","y, como hacía tiendas de campaña al igual que ellos, se quedó para que trabajaran juntos.","Todos los sábados discutía en la sinagoga, tratando de persuadir a judíos y a griegos.","Cuando Silas y Timoteo llegaron de Macedonia, Pablo se dedicó exclusivamente a la predicación, testificándoles a los judíos que Jesús era el Mesías.","Pero, cuando los judíos se opusieron a Pablo y lo insultaron, este se sacudió la ropa en señal de protesta y les dijo: «¡Caiga la sangre de ustedes sobre su propia cabeza! Estoy libre de responsabilidad. De ahora en adelante me dirigiré a los gentiles».","Entonces Pablo salió de la sinagoga y se fue a la casa de un tal Ticio Justo, que adoraba a Dios y que vivía al lado de la sinagoga.","Crispo, el jefe de la sinagoga, creyó en el Señor con toda su familia. También creyeron y fueron bautizados muchos de los corintios que oyeron a Pablo.","Una noche el Señor le dijo a Pablo en una visión: «No tengas miedo; sigue hablando y no te calles,","pues estoy contigo. Aunque te ataquen, no voy a dejar que nadie te haga daño, porque tengo mucha gente en esta ciudad».","Así que Pablo se quedó allí un año y medio, enseñando entre el pueblo la palabra de Dios.","Mientras Galión era gobernador[60] de Acaya, los judíos a una atacaron a Pablo y lo condujeron al tribunal.","—Este hombre —denunciaron ellos— anda persuadiendo a la gente a adorar a Dios de una manera que va en contra de nuestra ley.","Pablo ya iba a hablar cuando Galión les dijo: —Si ustedes los judíos estuvieran entablando una demanda sobre algún delito o algún crimen grave, sería razonable que los escuchara.","Pero, como se trata de cuestiones de palabras, de nombres y de su propia ley, arréglense entre ustedes. No quiero ser juez de tales cosas.","Así que mandó que los expulsaran del tribunal.","Entonces se abalanzaron todos sobre Sóstenes, el jefe de la sinagoga, y lo golpearon delante del tribunal. Pero Galión no le dio ninguna importancia al asunto.","Pablo permaneció en Corinto algún tiempo más. Después se despidió de los hermanos y emprendió el viaje rumbo a Siria, acompañado de Priscila y Aquila. En Cencreas, antes de embarcarse, se hizo rapar la cabeza a causa de un voto que había hecho.","Al llegar a Éfeso, Pablo se separó de sus acompañantes y entró en la sinagoga, donde se puso a discutir con los judíos.","Estos le pidieron que se quedara más tiempo con ellos. Él no accedió,","pero al despedirse les prometió: «Ya volveré, si Dios quiere». Y zarpó de Éfeso.","Cuando desembarcó en Cesarea, subió a Jerusalén a saludar a la iglesia y luego bajó a Antioquía.","Después de pasar algún tiempo allí, Pablo se fue a visitar una por una las congregaciones[61] de Galacia y Frigia, animando a todos los discípulos.","Por aquel entonces llegó a Éfeso un judío llamado Apolos, natural de Alejandría. Era un hombre ilustrado y convincente en el uso de las Escrituras.","Había sido instruido en el camino del Señor, y con gran fervor[62] hablaba y enseñaba con la mayor exactitud acerca de Jesús, aunque conocía solo el bautismo de Juan.","Comenzó a hablar valientemente en la sinagoga. Al oírlo Priscila y Aquila, lo tomaron a su cargo y le explicaron con mayor precisión el camino de Dios.","Como Apolos quería pasar a Acaya, los hermanos lo animaron y les escribieron a los discípulos de allá para que lo recibieran. Cuando llegó, ayudó mucho a quienes por la gracia habían creído,","pues refutaba vigorosamente en público a los judíos, demostrando por las Escrituras que Jesús es el Mesías."],
  19: ["Mientras Apolos estaba en Corinto, Pablo recorrió las regiones del interior y llegó a Éfeso. Allí encontró a algunos discípulos.","—¿Recibieron ustedes el Espíritu Santo cuando creyeron? —les preguntó. —No, ni siquiera hemos oído hablar del Espíritu Santo —respondieron.","—Entonces, ¿qué bautismo recibieron? —El bautismo de Juan.","Pablo les explicó: —El bautismo de Juan no era más que un bautismo de arrepentimiento. Él le decía al pueblo que creyera en el que venía después de él, es decir, en Jesús.","Al oír esto, fueron bautizados en el nombre del Señor Jesús.","Cuando Pablo les impuso las manos, el Espíritu Santo vino sobre ellos, y empezaron a hablar en lenguas y a profetizar.","Eran en total unos doce hombres.","Pablo entró en la sinagoga y habló allí con toda valentía durante tres meses. Discutía acerca del reino de Dios, tratando de convencerlos,","pero algunos se negaron obstinadamente a creer, y ante la congregación hablaban mal del Camino. Así que Pablo se alejó de ellos y formó un grupo aparte con los discípulos; y a diario debatía en la escuela de Tirano.","Esto continuó por espacio de dos años, de modo que todos los judíos y los griegos que vivían en la provincia de Asia llegaron a escuchar la palabra del Señor.","Dios hacía milagros extraordinarios por medio de Pablo,","a tal grado que a los enfermos les llevaban pañuelos y delantales que habían tocado el cuerpo de Pablo, y quedaban sanos de sus enfermedades, y los espíritus malignos salían de ellos.","Algunos judíos que andaban expulsando espíritus malignos intentaron invocar sobre los endemoniados el nombre del Señor Jesús. Decían: «¡En el nombre de Jesús, a quien Pablo predica, les ordeno que salgan!»","Esto lo hacían siete hijos de un tal Esceva, que era uno de los jefes de los sacerdotes judíos.","Un día el espíritu maligno les replicó: «Conozco a Jesús, y sé quién es Pablo, pero ustedes ¿quiénes son?»","Y abalanzándose sobre ellos, el hombre que tenía el espíritu maligno los dominó a todos. Los maltrató con tanta violencia que huyeron de la casa desnudos y heridos.","Cuando se enteraron los judíos y los griegos que vivían en Éfeso, el temor se apoderó de todos ellos, y el nombre del Señor Jesús era glorificado.","Muchos de los que habían creído llegaban ahora y confesaban públicamente sus prácticas malvadas.","Un buen número de los que practicaban la hechicería juntaron sus libros en un montón y los quemaron delante de todos. Cuando calcularon el precio de aquellos libros, resultó un total de cincuenta mil monedas de plata.[63]","Así la palabra del Señor crecía y se difundía con poder arrollador.","Después de todos estos sucesos, Pablo tomó la determinación de ir a Jerusalén, pasando por Macedonia y Acaya. Decía: «Después de estar allí, tengo que visitar Roma».","Entonces envió a Macedonia a dos de sus ayudantes, Timoteo y Erasto, mientras él se quedaba por algún tiempo en la provincia de Asia.","Por aquellos días se produjo un gran disturbio a propósito del Camino.","Un platero llamado Demetrio, que hacía figuras en plata del templo de Artemisa,[64] proporcionaba a los artesanos no poca ganancia.","Los reunió con otros obreros del ramo, y les dijo: —Compañeros, ustedes saben que obtenemos buenos ingresos de este oficio.","Les consta además que el tal Pablo ha logrado persuadir a mucha gente no solo en Éfeso, sino en casi toda la provincia de Asia. Él sostiene que no son dioses los que se hacen con las manos.","Ahora bien, no solo hay el peligro de que se desprestigie nuestro oficio, sino también de que el templo de la gran diosa Artemisa sea menospreciado, y que la diosa misma, a quien adoran toda la provincia de Asia y el mundo entero, sea despojada de su divina majestad.","Al oír esto, se enfurecieron y comenzaron a gritar: —¡Grande es Artemisa de los efesios!","En seguida toda la ciudad se alborotó. La turba en masa se precipitó en el teatro, arrastrando a Gayo y a Aristarco, compañeros de viaje de Pablo, que eran de Macedonia.","Pablo quiso presentarse ante la multitud, pero los discípulos no se lo permitieron.","Incluso algunas autoridades de la provincia, que eran amigos de Pablo, le enviaron un recado, rogándole que no se arriesgara a entrar en el teatro.","Había confusión en la asamblea. Cada uno gritaba una cosa distinta, y la mayoría ni siquiera sabía para qué se habían reunido.","Los judíos empujaron a un tal Alejandro hacia adelante, y algunos de entre la multitud lo sacaron para que tomara la palabra. Él agitó la mano para pedir silencio y presentar su defensa ante el pueblo.","Pero, cuando se dieron cuenta de que era judío, todos se pusieron a gritar al unísono como por dos horas: —¡Grande es Artemisa de los efesios!","El secretario del concejo municipal logró calmar a la multitud y dijo: —Ciudadanos de Éfeso, ¿acaso no sabe todo el mundo que la ciudad de Éfeso es guardiana del templo de la gran Artemisa y de su estatua bajada del cielo?","Ya que estos hechos son innegables, es preciso que ustedes se calmen y no hagan nada precipitadamente.","Ustedes han traído a estos hombres, aunque ellos no han cometido ningún sacrilegio ni han blasfemado contra nuestra diosa.","Así que, si Demetrio y sus compañeros de oficio tienen alguna queja contra alguien, para eso hay tribunales y gobernadores.[65] Vayan y presenten allí sus acusaciones unos contra otros.","Si tienen alguna otra demanda, que se resuelva en legítima asamblea.","Tal y como están las cosas, con los sucesos de hoy corremos el riesgo de que nos acusen de causar disturbios. ¿Qué razón podríamos dar de este alboroto, si no hay ninguna?","Dicho esto, despidió la asamblea."],
  20: ["Cuando cesó el alboroto, Pablo mandó llamar a los discípulos y, después de animarlos, se despidió y salió rumbo a Macedonia.","Recorrió aquellas regiones, alentando a los creyentes en muchas ocasiones, y por fin llegó a Grecia,","donde se quedó tres meses. Como los judíos tramaban un atentado contra él cuando estaba a punto de embarcarse para Siria, decidió regresar por Macedonia.","Lo acompañaron Sópater hijo de Pirro, de Berea; Aristarco y Segundo, de Tesalónica; Gayo, de Derbe; Timoteo; y por último, Tíquico y Trófimo, de la provincia de Asia.","Estos se adelantaron y nos esperaron en Troas.","Pero nosotros zarpamos de Filipos después de la fiesta de los Panes sin levadura, y a los cinco días nos reunimos con los otros en Troas, donde pasamos siete días.","El primer día de la semana nos reunimos para partir el pan. Como iba a salir al día siguiente, Pablo estuvo hablando a los creyentes, y prolongó su discurso hasta la medianoche.","En el cuarto del piso superior donde estábamos reunidos había muchas lámparas.","Un joven llamado Eutico, que estaba sentado en una ventana, comenzó a dormirse mientras Pablo alargaba su discurso. Cuando se quedó profundamente dormido, se cayó desde el tercer piso y lo recogieron muerto.","Pablo bajó, se echó sobre el joven y lo abrazó. «¡No se alarmen! —les dijo—. ¡Está vivo!»","Luego volvió a subir, partió el pan y comió. Siguió hablando hasta el amanecer, y entonces se fue.","Al joven se lo llevaron vivo a su casa, para gran consuelo de todos.","Nosotros, por nuestra parte, nos embarcamos anticipadamente y zarpamos para Asón, donde íbamos a recoger a Pablo. Así se había planeado, ya que él iba a hacer esa parte del viaje por tierra.","Cuando se encontró con nosotros en Asón, lo tomamos a bordo y fuimos a Mitilene.","Desde allí zarpamos al día siguiente y llegamos frente a Quío. Al otro día cruzamos en dirección a Samos, y un día después llegamos a Mileto.","Pablo había decidido pasar de largo a Éfeso para no demorarse en la provincia de Asia, porque tenía prisa por llegar a Jerusalén para el día de Pentecostés, si fuera posible.","Desde Mileto, Pablo mandó llamar a los ancianos de la iglesia de Éfeso.","Cuando llegaron, les dijo: «Ustedes saben cómo me porté todo el tiempo que estuve con ustedes, desde el primer día que vine a la provincia de Asia.","He servido al Señor con toda humildad y con lágrimas, a pesar de haber sido sometido a duras pruebas por las maquinaciones de los judíos.","Ustedes saben que no he vacilado en predicarles todo lo que les fuera de provecho, sino que les he enseñado públicamente y en las casas.","A judíos y a griegos les he instado a convertirse a Dios y a creer en nuestro Señor Jesús.","»Y ahora tengan en cuenta que voy a Jerusalén obligado[66] por el Espíritu, sin saber lo que allí me espera.","Lo único que sé es que en todas las ciudades el Espíritu Santo me asegura que me esperan prisiones y sufrimientos.","Sin embargo, considero que mi vida carece de valor para mí mismo, con tal de que termine mi carrera y lleve a cabo el servicio que me ha encomendado el Señor Jesús, que es el de dar testimonio del evangelio de la gracia de Dios.","»Escuchen, yo sé que ninguno de ustedes, entre quienes he andado predicando el reino de Dios, volverá a verme.","Por tanto, hoy les declaro que soy inocente de la sangre de todos,","porque sin vacilar les he proclamado todo el propósito de Dios.","Tengan cuidado de sí mismos y de todo el rebaño sobre el cual el Espíritu Santo los ha puesto como obispos para pastorear la iglesia de Dios,[67] que él adquirió con su propia sangre.[68]","Sé que después de mi partida entrarán en medio de ustedes lobos feroces que procurarán acabar con el rebaño.","Aun de entre ustedes mismos se levantarán algunos que enseñarán falsedades para arrastrar a los discípulos que los sigan.","Así que estén alerta. Recuerden que día y noche, durante tres años, no he dejado de amonestar con lágrimas a cada uno en particular.","»Ahora los encomiendo a Dios y al mensaje de su gracia, mensaje que tiene poder para edificarlos y darles herencia entre todos los santificados.","No he codiciado ni la plata ni el oro ni la ropa de nadie.","Ustedes mismos saben bien que estas manos se han ocupado de mis propias necesidades y de las de mis compañeros.","Con mi ejemplo les he mostrado que es preciso trabajar duro para ayudar a los necesitados, recordando las palabras del Señor Jesús: “Hay más dicha en dar que en recibir”».","Después de decir esto, Pablo se puso de rodillas con todos ellos y oró.","Todos lloraban inconsolablemente mientras lo abrazaban y lo besaban.","Lo que más los entristecía era su declaración de que ellos no volverían a verlo. Luego lo acompañaron hasta el barco."],
  21: ["Después de separarnos de ellos, zarpamos y navegamos directamente a Cos. Al día siguiente fuimos a Rodas, y de allí a Pátara.","Como encontramos un barco que iba para Fenicia, subimos a bordo y zarpamos.","Después de avistar Chipre y de pasar al sur de la isla, navegamos hacia Siria y llegamos a Tiro, donde el barco tenía que descargar.","Allí encontramos a los discípulos y nos quedamos con ellos siete días. Ellos, por medio del Espíritu, exhortaron a Pablo a que no subiera a Jerusalén.","Pero, al cabo de algunos días, partimos y continuamos nuestro viaje. Todos los discípulos, incluso las mujeres y los niños, nos acompañaron hasta las afueras de la ciudad, y allí en la playa nos arrodillamos y oramos.","Luego de despedirnos, subimos a bordo y ellos regresaron a sus hogares.","Nosotros continuamos nuestro viaje en barco desde Tiro y arribamos a Tolemaida, donde saludamos a los hermanos y nos quedamos con ellos un día.","Al día siguiente salimos y llegamos a Cesarea, y nos hospedamos en casa de Felipe el evangelista, que era uno de los siete;","este tenía cuatro hijas solteras que profetizaban.","Llevábamos allí varios días cuando bajó de Judea un profeta llamado Ágabo.","Este vino a vernos y, tomando el cinturón de Pablo, se ató con él de pies y manos, y dijo: —Así dice el Espíritu Santo: “De esta manera atarán los judíos de Jerusalén al dueño de este cinturón, y lo entregarán en manos de los gentiles”.","Al oír esto, nosotros y los de aquel lugar le rogamos a Pablo que no subiera a Jerusalén.","—¿Por qué lloran? ¡Me parten el alma! —respondió Pablo—. Por el nombre del Señor Jesús estoy dispuesto no solo a ser atado, sino también a morir en Jerusalén.","Como no se dejaba convencer, desistimos, exclamando: —¡Que se haga la voluntad del Señor!","Después de esto, acabamos los preparativos y subimos a Jerusalén.","Algunos de los discípulos de Cesarea nos acompañaron y nos llevaron a la casa de Mnasón, donde íbamos a alojarnos. Este era de Chipre, y uno de los primeros discípulos.","Cuando llegamos a Jerusalén, los creyentes nos recibieron calurosamente.","Al día siguiente Pablo fue con nosotros a ver a Jacobo, y todos los ancianos estaban presentes.","Después de saludarlos, Pablo les relató detalladamente lo que Dios había hecho entre los gentiles por medio de su ministerio.","Al oírlo, alabaron a Dios. Luego le dijeron a Pablo: «Ya ves, hermano, cuántos miles de judíos han creído, y todos ellos siguen aferrados a la ley.","Ahora bien, han oído decir que tú enseñas que se aparten de Moisés todos los judíos que viven entre los gentiles. Les recomiendas que no circunciden a sus hijos ni vivan según nuestras costumbres.","¿Qué vamos a hacer? Sin duda se van a enterar de que has llegado.","Por eso, será mejor que sigas nuestro consejo. Hay aquí entre nosotros cuatro hombres que tienen que cumplir un voto.","Llévatelos, toma parte en sus ritos de purificación y paga los gastos que corresponden al voto de rasurarse la cabeza. Así todos sabrán que no son ciertos esos informes acerca de ti, sino que tú también vives en obediencia a la ley.","En cuanto a los creyentes gentiles, ya les hemos comunicado por escrito nuestra decisión de que se abstengan de lo sacrificado a los ídolos, de sangre, de la carne de animales estrangulados y de la inmoralidad sexual».","Al día siguiente Pablo se llevó a los hombres y se purificó con ellos. Luego entró en el templo para dar aviso de la fecha en que vencería el plazo de la purificación y se haría la ofrenda por cada uno de ellos.","Cuando estaban a punto de cumplirse los siete días, unos judíos de la provincia de Asia vieron a Pablo en el templo. Alborotaron a toda la multitud y le echaron mano,","gritando: «¡Israelitas! ¡Ayúdennos! Este es el individuo que anda por todas partes enseñando a toda la gente contra nuestro pueblo, nuestra ley y este lugar. Además, hasta ha metido a unos griegos en el templo, y ha profanado este lugar santo».","Ya antes habían visto en la ciudad a Trófimo el efesio en compañía de Pablo, y suponían que Pablo lo había metido en el templo.","Toda la ciudad se alborotó. La gente se precipitó en masa, agarró a Pablo y lo sacó del templo a rastras, e inmediatamente se cerraron las puertas.","Estaban por matarlo, cuando se le informó al comandante del batallón romano que toda la ciudad de Jerusalén estaba amotinada.","En seguida tomó algunos centuriones con sus tropas, y bajó corriendo hacia la multitud. Al ver al comandante y a sus soldados, los amotinados dejaron de golpear a Pablo.","El comandante se abrió paso, lo arrestó y ordenó que lo sujetaran con dos cadenas. Luego preguntó quién era y qué había hecho.","Entre la multitud cada uno gritaba una cosa distinta. Como el comandante no pudo averiguar la verdad a causa del alboroto, mandó que condujeran a Pablo al cuartel.","Cuando Pablo llegó a las gradas, los soldados tuvieron que llevárselo en vilo debido a la violencia de la turba.","El pueblo en masa iba detrás gritando: «¡Que lo maten!»","Cuando los soldados estaban a punto de meterlo en el cuartel, Pablo le preguntó al comandante: —¿Me permite decirle algo? —¿Hablas griego? —replicó el comandante—.","¿No eres el egipcio que hace algún tiempo provocó una rebelión y llevó al desierto a cuatro mil guerrilleros?","—No, yo soy judío, natural de Tarso, una ciudad muy importante de Cilicia —le respondió Pablo—. Por favor, permítame hablarle al pueblo.","Con el permiso del comandante, Pablo se puso de pie en las gradas e hizo una señal con la mano a la multitud. Cuando todos guardaron silencio, les dijo en arameo:[69]"],
  22: ["«Padres y hermanos, escuchen ahora mi defensa».","Al oír que les hablaba en arameo, guardaron más silencio. Pablo continuó:","«Yo soy judío, nacido en Tarso de Cilicia, pero criado en esta ciudad. Bajo la tutela de Gamaliel recibí instrucción cabal en la ley de nuestros antepasados, y fui tan celoso de Dios como cualquiera de ustedes lo es hoy día.","Perseguí a muerte a los seguidores de este Camino, arrestando y echando en la cárcel a hombres y mujeres por igual,","y así lo pueden atestiguar el sumo sacerdote y todo el Consejo de ancianos. Incluso obtuve de parte de ellos cartas de extradición para nuestros hermanos judíos en Damasco, y fui allá con el fin de traer presos a Jerusalén a los que encontrara, para que fueran castigados.","»Sucedió que a eso del mediodía, cuando me acercaba a Damasco, una intensa luz del cielo relampagueó de repente a mi alrededor.","Caí al suelo y oí una voz que me decía: “Saulo, Saulo, ¿por qué me persigues?”","“¿Quién eres, Señor?”, pregunté. “Yo soy Jesús de Nazaret, a quien tú persigues”, me contestó él.","Los que me acompañaban vieron la luz, pero no percibieron la voz del que me hablaba.","“¿Qué debo hacer, Señor?”, le pregunté. “Levántate —dijo el Señor—, y entra en Damasco. Allí se te dirá todo lo que se ha dispuesto que hagas”.","Mis compañeros me llevaron de la mano hasta Damasco porque el resplandor de aquella luz me había dejado ciego.","»Vino a verme un tal Ananías, hombre devoto que observaba la ley y a quien respetaban mucho los judíos que allí vivían.","Se puso a mi lado y me dijo: “Hermano Saulo, ¡recibe la vista!” Y en aquel mismo instante recobré la vista y pude verlo.","Luego dijo: “El Dios de nuestros antepasados te ha escogido para que conozcas su voluntad, y para que veas al Justo y oigas las palabras de su boca.","Tú le serás testigo ante toda persona de lo que has visto y oído.","Y ahora, ¿qué esperas? Levántate, bautízate y lávate de tus pecados, invocando su nombre”.","»Cuando volví a Jerusalén, mientras oraba en el templo tuve una visión","y vi al Señor que me hablaba: “¡Date prisa! Sal inmediatamente de Jerusalén, porque no aceptarán tu testimonio acerca de mí”.","“Señor —le respondí—, ellos saben que yo andaba de sinagoga en sinagoga encarcelando y azotando a los que creen en ti;","y, cuando se derramaba la sangre de tu testigo[70] Esteban, ahí estaba yo, dando mi aprobación y cuidando la ropa de quienes lo mataban”.","Pero el Señor me replicó: “Vete; yo te enviaré lejos, a los gentiles”».","La multitud estuvo escuchando a Pablo hasta que pronunció esas palabras. Entonces levantaron la voz y gritaron: «¡Bórralo de la tierra! ¡Ese tipo no merece vivir!»","Como seguían gritando, tirando sus mantos y arrojando polvo al aire,","el comandante ordenó que metieran a Pablo en el cuartel. Mandó que lo interrogaran a latigazos con el fin de averiguar por qué gritaban así contra él.","Cuando lo estaban sujetando con cadenas para azotarlo, Pablo le dijo al centurión que estaba allí: —¿Permite la ley que ustedes azoten a un ciudadano romano antes de ser juzgado?","Al oír esto, el centurión fue y avisó al comandante. —¿Qué va a hacer usted? Resulta que ese hombre es ciudadano romano.","El comandante se acercó a Pablo y le dijo: —Dime, ¿eres ciudadano romano? —Sí, lo soy.","—A mí me costó una fortuna adquirir mi ciudadanía —le dijo el comandante. —Pues yo la tengo de nacimiento —replicó Pablo.","Los que iban a interrogarlo se retiraron en seguida. Al darse cuenta de que Pablo era ciudadano romano, el comandante mismo se asustó de haberlo encadenado.","Al día siguiente, como el comandante quería saber con certeza de qué acusaban los judíos a Pablo, lo desató y mandó que se reunieran los jefes de los sacerdotes y el Consejo en pleno. Luego llevó a Pablo para que compareciera ante ellos."],
  23: ["Pablo se quedó mirando fijamente al Consejo y dijo: —Hermanos, hasta hoy yo he actuado delante de Dios con toda buena conciencia.","Ante esto, el sumo sacerdote Ananías ordenó a los que estaban cerca de Pablo que lo golpearan en la boca.","—¡Hipócrita,[71] a usted también lo va a golpear Dios! —reaccionó Pablo—. ¡Ahí está sentado para juzgarme según la ley!, ¿y usted mismo viola la ley al mandar que me golpeen?","Los que estaban junto a Pablo le interpelaron: —¿Cómo te atreves a insultar al sumo sacerdote de Dios?","—Hermanos, no me había dado cuenta de que es el sumo sacerdote —respondió Pablo—; de hecho está escrito: “No hables mal del jefe de tu pueblo”.[72]","Pablo, sabiendo que unos de ellos eran saduceos y los demás fariseos, exclamó en el Consejo: —Hermanos, yo soy fariseo de pura cepa. Me están juzgando porque he puesto mi esperanza en la resurrección de los muertos.","Apenas dijo esto, surgió un altercado entre los fariseos y los saduceos, y la asamblea quedó dividida.","(Los saduceos sostienen que no hay resurrección, ni ángeles ni espíritus; los fariseos, en cambio, reconocen todo esto).","Se produjo un gran alboroto, y algunos de los maestros de la ley que eran fariseos se pusieron de pie y protestaron. «No encontramos ningún delito en este hombre —dijeron—. ¿Acaso no podría haberle hablado un espíritu o un ángel?»","Se tornó tan violento el altercado que el comandante tuvo miedo de que hicieran pedazos a Pablo. Así que ordenó a los soldados que bajaran para sacarlo de allí por la fuerza y llevárselo al cuartel.","A la noche siguiente el Señor se apareció a Pablo, y le dijo: «¡Ánimo! Así como has dado testimonio de mí en Jerusalén, es necesario que lo des también en Roma».","Muy de mañana los judíos tramaron una conspiración y juraron bajo maldición no comer ni beber hasta que lograran matar a Pablo.","Más de cuarenta hombres estaban implicados en esta conspiración.","Se presentaron ante los jefes de los sacerdotes y los ancianos, y les dijeron: —Nosotros hemos jurado bajo maldición no comer nada hasta que logremos matar a Pablo.","Ahora, con el respaldo del Consejo, pídanle al comandante que haga comparecer al reo ante ustedes, con el pretexto de obtener información más precisa sobre su caso. Nosotros estaremos listos para matarlo en el camino.","Pero, cuando el hijo de la hermana de Pablo se enteró de esta emboscada, entró en el cuartel y avisó a Pablo.","Este llamó entonces a uno de los centuriones y le pidió: —Lleve a este joven al comandante, porque tiene algo que decirle.","Así que el centurión lo llevó al comandante, y le dijo: —El preso Pablo me llamó y me pidió que le trajera este joven, porque tiene algo que decirle.","El comandante tomó de la mano al joven, lo llevó aparte y le preguntó: —¿Qué quieres decirme?","—Los judíos se han puesto de acuerdo para pedirle a usted que mañana lleve a Pablo ante el Consejo con el pretexto de obtener información más precisa acerca de él.","No se deje convencer, porque más de cuarenta de ellos lo esperan emboscados. Han jurado bajo maldición no comer ni beber hasta que hayan logrado matarlo. Ya están listos; solo aguardan a que usted les conceda su petición.","El comandante despidió al joven con esta advertencia: —No le digas a nadie que me has informado de esto.","Entonces el comandante llamó a dos de sus centuriones y les ordenó: —Alisten un destacamento de doscientos soldados de infantería, setenta de caballería y doscientos lanceros para que vayan a Cesarea esta noche a las nueve.[73]","Y preparen cabalgaduras para llevar a Pablo sano y salvo al gobernador Félix.","Además, escribió una carta en estos términos:","Claudio Lisias, a su excelencia el gobernador Félix: Saludos.","Los judíos prendieron a este hombre y estaban a punto de matarlo, pero yo llegué con mis soldados y lo rescaté, porque me había enterado de que es ciudadano romano.","Yo quería saber de qué lo acusaban, así que lo llevé al Consejo judío.","Descubrí que lo acusaban de algunas cuestiones de su ley, pero no había contra él cargo alguno que mereciera la muerte o la cárcel.","Cuando me informaron que se tramaba una conspiración contra este hombre, decidí enviarlo a usted en seguida. También les ordené a sus acusadores que expongan delante de usted los cargos que tengan contra él.","Así que los soldados, según se les había ordenado, tomaron a Pablo y lo llevaron de noche hasta Antípatris.","Al día siguiente dejaron que la caballería siguiera con él mientras ellos volvían al cuartel.","Cuando la caballería llegó a Cesarea, le entregaron la carta al gobernador y le presentaron también a Pablo.","Félix leyó la carta y preguntó de qué provincia era. Al enterarse de que Pablo era de Cilicia,","le dijo: «Te daré audiencia cuando lleguen tus acusadores». Y ordenó que lo dejaran bajo custodia en el palacio de Herodes."],
  24: ["Cinco días después, el sumo sacerdote Ananías bajó a Cesarea con algunos de los ancianos y un abogado llamado Tértulo, para presentar ante el gobernador las acusaciones contra Pablo.","Cuando se hizo comparecer al acusado, Tértulo expuso su caso ante Félix: —Excelentísimo Félix, bajo su mandato hemos disfrutado de un largo período de paz, y gracias a la previsión suya se han llevado a cabo reformas en pro de esta nación.","En todas partes y en toda ocasión reconocemos esto con profunda gratitud.","Pero, a fin de no importunarlo más, le ruego que, con la bondad que lo caracteriza, nos escuche brevemente.","Hemos descubierto que este hombre es una plaga que por todas partes anda provocando disturbios entre los judíos. Es cabecilla de la secta de los nazarenos.","Incluso trató de profanar el templo; por eso lo prendimos.","Usted[74] mismo, al interrogarlo, podrá cerciorarse de la verdad de todas las acusaciones que presentamos contra él.","Los judíos corroboraron la acusación, afirmando que todo esto era cierto.","Cuando el gobernador, con un gesto, le concedió la palabra, Pablo respondió: —Sé que desde hace muchos años usted ha sido juez de esta nación; así que de buena gana presento mi defensa.","Usted puede comprobar fácilmente que no hace más de doce días que subí a Jerusalén para adorar.","Mis acusadores no me encontraron discutiendo con nadie en el templo, ni promoviendo motines entre la gente en las sinagogas ni en ninguna otra parte de la ciudad.","Tampoco pueden probarle a usted las cosas de que ahora me acusan.","Sin embargo, esto sí confieso: que adoro al Dios de nuestros antepasados siguiendo este Camino que mis acusadores llaman secta, pues estoy de acuerdo con todo lo que enseña la ley y creo lo que está escrito en los profetas.","Tengo en Dios la misma esperanza que estos hombres profesan, de que habrá una resurrección de los justos y de los injustos.","En todo esto procuro conservar siempre limpia mi conciencia delante de Dios y de los hombres.","»Después de una ausencia de varios años, volví a Jerusalén para traerle donativos a mi pueblo y presentar ofrendas.","En esto estaba, habiéndome ya purificado, cuando me encontraron en el templo. No me acompañaba ninguna multitud, ni estaba implicado en ningún disturbio.","Los que me vieron eran algunos judíos de la provincia de Asia, y son ellos los que deberían estar delante de usted para formular sus acusaciones, si es que tienen algo contra mí.","De otro modo, estos que están aquí deberían declarar qué delito hallaron en mí cuando comparecí ante el Consejo,","a no ser lo que exclamé en presencia de ellos: “Es por la resurrección de los muertos por lo que hoy me encuentro procesado delante de ustedes”».","Entonces Félix, que estaba bien informado del Camino, suspendió la sesión. —Cuando venga el comandante Lisias, decidiré su caso —les dijo.","Luego le ordenó al centurión que mantuviera custodiado a Pablo, pero que le diera cierta libertad y permitiera que sus amigos lo atendieran.","Algunos días después llegó Félix con su esposa Drusila, que era judía. Mandó llamar a Pablo y lo escuchó hablar acerca de la fe en Cristo Jesús.","Al disertar Pablo sobre la justicia, el dominio propio y el juicio venidero, Félix tuvo miedo y le dijo: «¡Basta por ahora! Puedes retirarte. Cuando sea oportuno te mandaré llamar otra vez».","Félix también esperaba que Pablo le ofreciera dinero; por eso mandaba llamarlo con frecuencia y conversaba con él.","Transcurridos dos años, Félix tuvo como sucesor a Porcio Festo, pero, como Félix quería congraciarse con los judíos, dejó preso a Pablo."],
  25: ["Tres días después de llegar a la provincia, Festo subió de Cesarea a Jerusalén.","Entonces los jefes de los sacerdotes y los dirigentes de los judíos presentaron sus acusaciones contra Pablo.","Insistentemente le pidieron a Festo que les hiciera el favor de trasladar a Pablo a Jerusalén. Lo cierto es que ellos estaban preparando una emboscada para matarlo en el camino.","Festo respondió: «Pablo está preso en Cesarea, y yo mismo partiré en breve para allá.","Que vayan conmigo algunos de los dirigentes de ustedes y formulen allí sus acusaciones contra él, si es que ha hecho algo malo».","Después de pasar entre los judíos unos ocho o diez días, Festo bajó a Cesarea, y al día siguiente convocó al tribunal y mandó que le trajeran a Pablo.","Cuando este se presentó, los judíos que habían bajado de Jerusalén lo rodearon, formulando contra él muchas acusaciones graves que no podían probar.","Pablo se defendía: —No he cometido ninguna falta ni contra la ley de los judíos ni contra el templo ni contra el emperador.","Pero Festo, queriendo congraciarse con los judíos, le preguntó: —¿Estás dispuesto a subir a Jerusalén para ser juzgado allí ante mí?","Pablo contestó: —Ya estoy ante el tribunal del emperador, que es donde se me debe juzgar. No les he hecho ningún agravio a los judíos, como usted sabe muy bien.","Si soy culpable de haber hecho algo que merezca la muerte, no me niego a morir. Pero, si no son ciertas las acusaciones que estos judíos formulan contra mí, nadie tiene el derecho de entregarme a ellos para complacerlos. ¡Apelo al emperador!","Después de consultar con sus asesores, Festo declaró: —Has apelado al emperador. ¡Al emperador irás!","Pasados algunos días, el rey Agripa y Berenice llegaron a Cesarea para saludar a Festo.","Como se entretuvieron allí varios días, Festo le presentó al rey el caso de Pablo. —Hay aquí un hombre —le dijo— que Félix dejó preso.","Cuando fui a Jerusalén, los jefes de los sacerdotes y los ancianos de los judíos presentaron acusaciones contra él y exigieron que se le condenara.","Les respondí que no es costumbre de los romanos entregar a ninguna persona sin antes concederle al acusado un careo con sus acusadores, y darle la oportunidad de defenderse de los cargos.","Cuando acudieron a mí, no dilaté el caso, sino que convoqué al tribunal el día siguiente y mandé traer a este hombre.","Al levantarse para hablar, sus acusadores no alegaron en su contra ninguno de los delitos que yo había supuesto.","Más bien, tenían contra él algunas cuestiones tocantes a su propia religión y sobre un tal Jesús, ya muerto, que Pablo sostiene que está vivo.","Yo no sabía cómo investigar tales cuestiones, así que le pregunté si estaba dispuesto a ir a Jerusalén para ser juzgado allí con respecto a esos cargos.","Pero, como Pablo apeló para que se le reservara el fallo al emperador,[75] ordené que quedara detenido hasta ser remitido a Roma.[76]","—A mí también me gustaría oír a ese hombre —le dijo Agripa a Festo. —Pues mañana mismo lo oirá usted —le contestó Festo.","Al día siguiente Agripa y Berenice se presentaron con gran pompa, y entraron en la sala de la audiencia acompañados por oficiales de alto rango y por las personalidades más distinguidas de la ciudad. Festo mandó que le trajeran a Pablo,","y dijo: —Rey Agripa y todos los presentes: Aquí tienen a este hombre. Todo el pueblo judío me ha presentado una demanda contra él, tanto en Jerusalén como aquí en Cesarea, pidiendo a gritos su muerte.","He llegado a la conclusión de que él no ha hecho nada que merezca la muerte, pero, como apeló al emperador, he decidido enviarlo a Roma.","El problema es que no tengo definido nada que escribir al soberano acerca de él. Por eso lo he hecho comparecer ante ustedes, y especialmente delante de usted, rey Agripa, para que como resultado de esta investigación tenga yo algunos datos para mi carta;","me parece absurdo enviar un preso sin especificar los cargos contra él."],
  26: ["Entonces Agripa le dijo a Pablo: —Tienes permiso para defenderte. Pablo hizo un ademán con la mano y comenzó así su defensa:","—Rey Agripa, para mí es un privilegio presentarme hoy ante usted para defenderme de las acusaciones de los judíos,","sobre todo porque usted está bien informado de todas las tradiciones y controversias de los judíos. Por eso le ruego que me escuche con paciencia.","»Todos los judíos saben cómo he vivido desde que era niño, desde mi edad temprana entre mi gente y también en Jerusalén.","Ellos me conocen desde hace mucho tiempo y pueden atestiguar, si quieren, que viví como fariseo, de acuerdo con la secta más estricta de nuestra religión.","Y ahora me juzgan por la esperanza que tengo en la promesa que Dios hizo a nuestros antepasados.","Esta es la promesa que nuestras doce tribus esperan alcanzar rindiendo culto a Dios con diligencia día y noche. Es por esta esperanza, oh rey, por lo que me acusan los judíos.","¿Por qué les parece a ustedes increíble que Dios resucite a los muertos?","»Pues bien, yo mismo estaba convencido de que debía hacer todo lo posible por combatir el nombre de Jesús de Nazaret.","Eso es precisamente lo que hice en Jerusalén. Con la autoridad de los jefes de los sacerdotes metí en la cárcel a muchos de los santos y, cuando los mataban, yo manifestaba mi aprobación.","Muchas veces anduve de sinagoga en sinagoga castigándolos para obligarlos a blasfemar. Mi obsesión contra ellos me llevaba al extremo de perseguirlos incluso en ciudades del extranjero.","»En uno de esos viajes iba yo hacia Damasco con la autoridad y la comisión de los jefes de los sacerdotes.","A eso del mediodía, oh rey, mientras iba por el camino, vi una luz del cielo, más refulgente que el sol, que con su resplandor nos envolvió a mí y a mis acompañantes.","Todos caímos al suelo, y yo oí una voz que me decía en arameo:[77] “Saulo, Saulo, ¿por qué me persigues? ¿Qué sacas con darte cabezazos contra la pared?”[78]","Entonces pregunté: “¿Quién eres, Señor?” “Yo soy Jesús, a quien tú persigues —me contestó el Señor—.","Ahora, ponte en pie y escúchame. Me he aparecido a ti con el fin de designarte siervo y testigo de lo que has visto de mí y de lo que te voy a revelar.","Te libraré de tu propio pueblo y de los gentiles. Te envío a estos","para que les abras los ojos y se conviertan de las tinieblas a la luz, y del poder de Satanás a Dios, a fin de que, por la fe en mí, reciban el perdón de los pecados y la herencia entre los santificados”.","»Así que, rey Agripa, no fui desobediente a esa visión celestial.","Al contrario, comenzando con los que estaban en Damasco, siguiendo con los que estaban en Jerusalén y en toda Judea, y luego con los gentiles, a todos les prediqué que se arrepintieran y se convirtieran a Dios, y que demostraran su arrepentimiento con sus buenas obras.","Solo por eso los judíos me prendieron en el templo y trataron de matarme.","Pero Dios me ha ayudado hasta hoy, y así me mantengo firme, testificando a grandes y pequeños. No he dicho sino lo que los profetas y Moisés ya dijeron que sucedería:","que el Cristo padecería y que, siendo el primero en resucitar, proclamaría la luz a su propio pueblo y a los gentiles».","Al llegar Pablo a este punto de su defensa, Festo interrumpió. —¡Estás loco, Pablo! —le gritó—. El mucho estudio te ha hecho perder la cabeza.","—No estoy loco, excelentísimo Festo —contestó Pablo—. Lo que digo es cierto y sensato.","El rey está familiarizado con estas cosas, y por eso hablo ante él con tanto atrevimiento. Estoy convencido de que nada de esto ignora, porque no sucedió en un rincón.","Rey Agripa, ¿cree usted en los profetas? ¡A mí me consta que sí!","—Un poco más y me convences de hacerme cristiano[79] —le dijo Agripa.","—Sea por poco o por mucho —le replicó Pablo—, le pido a Dios que no solo usted, sino también todos los que me están escuchando hoy lleguen a ser como yo, aunque sin estas cadenas.","Se levantó el rey, y también el gobernador, Berenice y los que estaban sentados con ellos.","Al retirarse, decían entre sí: —Este hombre no ha hecho nada que merezca la muerte ni la cárcel.","Y Agripa le dijo a Festo: —Se podría poner en libertad a este hombre si no hubiera apelado al emperador."],
  27: ["Cuando se decidió que navegáramos rumbo a Italia, entregaron a Pablo y a algunos otros presos a un centurión llamado Julio, que pertenecía al batallón imperial.","Subimos a bordo de un barco, con matrícula de Adramitio, que estaba a punto de zarpar hacia los puertos de la provincia de Asia, y nos hicimos a la mar. Nos acompañaba Aristarco, un macedonio de Tesalónica.","Al día siguiente hicimos escala en Sidón; y Julio, con mucha amabilidad, le permitió a Pablo visitar a sus amigos para que lo atendieran.","Desde Sidón zarpamos y navegamos al abrigo de Chipre, porque los vientos nos eran contrarios.","Después de atravesar el mar frente a las costas de Cilicia y Panfilia, arribamos a Mira de Licia.","Allí el centurión encontró un barco de Alejandría que iba para Italia, y nos hizo subir a bordo.","Durante muchos días la navegación fue lenta, y a duras penas llegamos frente a Gnido. Como el viento nos era desfavorable para seguir el rumbo trazado, navegamos al amparo de Creta, frente a Salmona.","Seguimos con dificultad a lo largo de la costa y llegamos a un lugar llamado Buenos Puertos, cerca de la ciudad de Lasea.","Se había perdido mucho tiempo, y era peligrosa la navegación por haber pasado ya la fiesta del ayuno.[80] Así que Pablo les advirtió:","«Señores, veo que nuestro viaje va a ser desastroso y que va a causar mucho perjuicio tanto para el barco y su carga como para nuestras propias vidas».","Pero el centurión, en vez de hacerle caso, siguió el consejo del timonel y del dueño del barco.","Como el puerto no era adecuado para invernar, la mayoría decidió que debíamos seguir adelante, con la esperanza de llegar a Fenice, puerto de Creta que da al suroeste y al noroeste, y pasar allí el invierno.","Cuando comenzó a soplar un viento suave del sur, creyeron que podían conseguir lo que querían, así que levaron anclas y navegaron junto a la costa de Creta.","Poco después se nos vino encima un viento huracanado, llamado Nordeste, que venía desde la isla.","El barco quedó atrapado por la tempestad y no podía hacerle frente al viento, así que nos dejamos llevar a la deriva.","Mientras pasábamos al abrigo de un islote llamado Cauda, a duras penas pudimos sujetar el bote salvavidas.","Después de subirlo a bordo, amarraron con sogas todo el casco del barco para reforzarlo. Temiendo que fueran a encallar en los bancos de arena de la Sirte, echaron el ancla flotante y dejaron el barco a la deriva.","Al día siguiente, dado que la tempestad seguía arremetiendo con mucha fuerza contra nosotros, comenzaron a arrojar la carga por la borda.","Al tercer día, con sus propias manos arrojaron al mar los aparejos del barco.","Como pasaron muchos días sin que aparecieran ni el sol ni las estrellas, y la tempestad seguía arreciando, perdimos al fin toda esperanza de salvarnos.","Llevábamos ya mucho tiempo sin comer, así que Pablo se puso en medio de todos y dijo: «Señores, debían haber seguido mi consejo y no haber zarpado de Creta; así se habrían ahorrado este perjuicio y esta pérdida.","Pero ahora los exhorto a cobrar ánimo, porque ninguno de ustedes perderá la vida; solo se perderá el barco.","Anoche se me apareció un ángel del Dios a quien pertenezco y a quien sirvo,","y me dijo: “No tengas miedo, Pablo. Tienes que comparecer ante el emperador; y Dios te ha concedido la vida de todos los que navegan contigo”.","Así que ¡ánimo, señores! Confío en Dios que sucederá tal y como se me dijo.","Sin embargo, tenemos que encallar en alguna isla».","Ya habíamos pasado catorce noches a la deriva por el mar Adriático[81] cuando a eso de la medianoche los marineros presintieron que se aproximaban a tierra.","Echaron la sonda y encontraron que el agua tenía unos treinta y siete metros de profundidad. Más adelante volvieron a echar la sonda y encontraron que tenía cerca de veintisiete metros[82] de profundidad.","Temiendo que fuéramos a estrellarnos contra las rocas, echaron cuatro anclas por la popa y se pusieron a rogar que amaneciera.","En un intento por escapar del barco, los marineros comenzaron a bajar el bote salvavidas al mar, con el pretexto de que iban a echar algunas anclas desde la proa.","Pero Pablo les advirtió al centurión y a los soldados: «Si esos no se quedan en el barco, no podrán salvarse ustedes».","Así que los soldados cortaron las amarras del bote salvavidas y lo dejaron caer al agua.","Estaba a punto de amanecer cuando Pablo animó a todos a tomar alimento: «Hoy hace ya catorce días que ustedes están con la vida en un hilo, y siguen sin probar bocado.","Les ruego que coman algo, pues lo necesitan para sobrevivir. Ninguno de ustedes perderá ni un solo cabello de la cabeza».","Dicho esto, tomó pan y dio gracias a Dios delante de todos. Luego lo partió y comenzó a comer.","Todos se animaron y también comieron.","Éramos en total doscientas setenta y seis personas en el barco.","Una vez satisfechos, aligeraron el barco echando el trigo al mar.","Cuando amaneció, no reconocieron la tierra, pero vieron una bahía que tenía playa, donde decidieron encallar el barco a como diera lugar.","Cortaron las anclas y las dejaron caer en el mar, desatando a la vez las amarras de los timones. Luego izaron a favor del viento la vela de proa y se dirigieron a la playa.","Pero el barco fue a dar en un banco de arena y encalló. La proa se encajó en el fondo y quedó varada, mientras la popa se hacía pedazos al embate de las olas.","Los soldados pensaron matar a los presos para que ninguno escapara a nado.","Pero el centurión quería salvarle la vida a Pablo, y les impidió llevar a cabo el plan. Dio orden de que los que pudieran nadar saltaran primero por la borda para llegar a tierra,","y de que los demás salieran valiéndose de tablas o de restos del barco. De esta manera todos llegamos sanos y salvos a tierra."],
  28: ["Una vez a salvo, nos enteramos de que la isla se llamaba Malta.","Los isleños nos trataron con toda clase de atenciones. Encendieron una fogata y nos invitaron a acercarnos, porque estaba lloviendo y hacía frío.","Sucedió que Pablo recogió un montón de leña y la estaba echando al fuego cuando una víbora que huía del calor se le prendió en la mano.","Al ver la serpiente colgada de la mano de Pablo, los isleños se pusieron a comentar entre sí: «Sin duda este hombre es un asesino, pues aunque se salvó del mar, la justicia divina no va a consentir que siga con vida».","Pero Pablo sacudió la mano y la serpiente cayó en el fuego, y él no sufrió ningún daño.","La gente esperaba que se hinchara o cayera muerto de repente, pero, después de esperar un buen rato y de ver que nada extraño le sucedía, cambiaron de parecer y decían que era un dios.","Cerca de allí había una finca que pertenecía a Publio, el funcionario principal de la isla. Este nos recibió en su casa con amabilidad y nos hospedó durante tres días.","El padre de Publio estaba en cama, enfermo con fiebre y disentería. Pablo entró a verlo y, después de orar, le impuso las manos y lo sanó.","Como consecuencia de esto, los demás enfermos de la isla también acudían y eran sanados.","Nos colmaron de muchas atenciones y nos proveyeron de todo lo necesario para el viaje.","Al cabo de tres meses en la isla, zarpamos en un barco que había invernado allí. Era una nave de Alejandría que tenía por insignia a los dioses Dióscuros.[83]","Hicimos escala en Siracusa, donde nos quedamos tres días.","Desde allí navegamos bordeando la costa y llegamos a Regio. Al día siguiente se levantó el viento del sur, y al segundo día llegamos a Poteoli.","Allí encontramos a algunos creyentes que nos invitaron a pasar una semana con ellos. Y por fin llegamos a Roma.","Los hermanos de Roma, habiéndose enterado de nuestra situación, salieron hasta el Foro de Apio y Tres Tabernas a recibirnos. Al verlos, Pablo dio gracias a Dios y cobró ánimo.","Cuando llegamos a Roma, a Pablo se le permitió tener su domicilio particular, con un soldado que lo custodiara.","Tres días más tarde, Pablo convocó a los dirigentes de los judíos. Cuando estuvieron reunidos, les dijo: —A mí, hermanos, a pesar de no haber hecho nada contra mi pueblo ni contra las costumbres de nuestros antepasados, me arrestaron en Jerusalén y me entregaron a los romanos.","Estos me interrogaron y quisieron soltarme por no ser yo culpable de ningún delito que mereciera la muerte.","Cuando los judíos se opusieron, me vi obligado a apelar al emperador, pero no porque tuviera alguna acusación que presentar contra mi nación.","Por este motivo he pedido verlos y hablar con ustedes. Precisamente por la esperanza de Israel estoy encadenado.","—Nosotros no hemos recibido ninguna carta de Judea que tenga que ver contigo —le contestaron ellos—, ni ha llegado ninguno de los hermanos de allá con malos informes o que haya hablado mal de ti.","Pero queremos oír tu punto de vista, porque lo único que sabemos es que en todas partes se habla en contra de esa secta.","Señalaron un día para reunirse con Pablo, y acudieron en mayor número a la casa donde estaba alojado. Desde la mañana hasta la tarde estuvo explicándoles y testificándoles acerca del reino de Dios y tratando de convencerlos respecto a Jesús, partiendo de la ley de Moisés y de los profetas.","Unos se convencieron por lo que él decía, pero otros se negaron a creer.","No pudieron ponerse de acuerdo entre sí, y comenzaron a irse cuando Pablo añadió esta última declaración: «Con razón el Espíritu Santo les habló a sus antepasados por medio del profeta Isaías diciendo:","»“Ve a este pueblo y dile: ‘Por mucho que oigan, no entenderán; por mucho que vean, no percibirán’.","Porque el corazón de este pueblo se ha vuelto insensible; se les han embotado los oídos, y se les han cerrado los ojos. De lo contrario, verían con los ojos, oirían con los oídos, entenderían con el corazón y se convertirían, y yo los sanaría”.[84]","»Por tanto, quiero que sepan que esta salvación de Dios se ha enviado a los gentiles, y ellos sí escucharán».[85]","Durante dos años completos permaneció Pablo en la casa que tenía alquilada, y recibía a todos los que iban a verlo.","Y predicaba el reino de Dios y enseñaba acerca del Señor Jesucristo sin impedimento y sin temor alguno."],
};
